const SignaturePad = forwardRef(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = getCanvasContext();
      if (ctx) {
        ctx.strokeStyle = colors.textColor;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
      }
    }
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    let clientX = e.clientX;
    let clientY = e.clientY;
    if (e.touches && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    }
    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY,
    };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath();
    ctx.moveTo(x, y);
    setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const stopDrawing = (e) => {
    if (e && e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    ctx.closePath();
    setIsDrawing(false);
    if (canvasRef.current) {
        onSignatureChange(canvasRef.current.toDataURL());
    }
  };

  const clearSignature = () => {
    const ctx = getCanvasContext();
    if (!ctx || !canvasRef.current) return;
    ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    onSignatureChange('');
  };

  useImperativeHandle(ref, () => ({ clear: clearSignature }));

  return (
    <div>
      <canvas
        ref={canvasRef}
        width="600"
        height="200"
        style={styles.signatureCanvas}
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
      />
      <div style={{ marginTop: '0.5rem' }}>
        <button type="button" onClick={clearSignature} style={{...styles.button, ...styles.buttonSecondary}}>Clear</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
    };

    useEffect(() => {
        if (isCameraOpen) {
            const startCamera = async () => {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ 
                        video: { facingMode: 'environment' } 
                    });
                    streamRef.current = stream;
                    if (videoRef.current) videoRef.current.srcObject = stream;
                } catch (err) {
                    try {
                        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
                        streamRef.current = stream;
                        if (videoRef.current) videoRef.current.srcObject = stream;
                    } catch (fallbackErr) {
                        alert("Could not access the camera.");
                        setIsCameraOpen(false);
                    }
                }
            };
            startCamera();
        } else {
            stopStream();
        }
        return () => stopStream();
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas && video.readyState >= 3) {
            const context = canvas.getContext('2d');
            if (context) {
                canvas.width = video.videoWidth;
                canvas.height = video.videoHeight;
                context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
                onImageUpload(canvas.toDataURL('image/jpeg'));
                setIsCameraOpen(false);
            }
        }
    };

    return (
        <div style={styles.formGroup}>
            <label style={styles.label}>{label}</label>
            <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, ...styles.buttonSecondary, marginRight: 0 }}>
                Take Photo
            </button>
            {imageSrc && (
                <div style={{ marginTop: '1rem', display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <img src={imageSrc} alt="Preview" style={{ maxWidth: '150px', maxHeight: '150px', borderRadius: '4px', border: `1px solid ${colors.lightGray}` }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, ...styles.buttonDanger, marginRight: 0 }}>Remove</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={styles.modalBackdrop}>
                    <div style={styles.modalContent}>
                         <div style={styles.modalHeader}>
                            <h2 style={{...styles.h2, marginTop: 0}}>Take Photo</h2>
                            <button onClick={() => setIsCameraOpen(false)} style={styles.closeButton}>&times;</button>
                        </div>
                        <video ref={videoRef} autoPlay playsInline style={{ width: '100%', borderRadius: '4px', marginBottom: '1rem', background: colors.darkGray }}></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ textAlign: 'center' }}>
                            <button type="button" onClick={capturePhoto} style={styles.button}>Capture</button>
                            <button type="button" onClick={() => setIsCameraOpen(false)} style={{...styles.button, ...styles.buttonSecondary}}>Cancel</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const TattooConsentForm = ({ onSubmit, onBack }) => {
