    const localSubmit = (e) => {
        e.preventDefault();
        if (!formData.fullName || !formData.receivedCareInstructions || !formData.signature) {
            alert('Please fill out all required fields.'); return;
        }
        onSubmit(formData, 'tattoo');
    };

    return (
        <form onSubmit={localSubmit}>
            <h2 style={{...styles.h2, textAlign: 'center', border: 'none'}}>Tattoo Consent</h2>
            <div style={styles.formRow}>
                <div style={styles.formField}><label style={styles.label}>Full Name: *</label><input type="text" name="fullName" value={formData.fullName} onChange={handleInputChange} required style={styles.input} /></div>
                <div style={styles.formField}><label style={styles.label}>Date:</label><input type="date" name="date" value={formData.date} onChange={handleInputChange} style={styles.input} /></div>
            </div>
            <div style={styles.formGroup}><label style={styles.label}>Address:</label><input type="text" name="address" value={formData.address} onChange={handleInputChange} style={styles.input} /></div>
            <div style={styles.formRow}>
                <div style={{...styles.formField, flex: 2}}><label style={styles.label}>City:</label><input type="text" name="city" value={formData.city} onChange={handleInputChange} style={styles.input} /></div>
                <div style={styles.formField}><label style={styles.label}>State:</label><input type="text" name="state" value={formData.state} onChange={handleInputChange} style={styles.input} /></div>
            </div>
            <div style={styles.formGroup}><label style={styles.label}>Phone#:</label><input type="tel" name="phone" value={formData.phone} onChange={handleInputChange} style={styles.input} /></div>
            <ImageUploader label="Photo of ID:" onImageUpload={(url) => setFormData(p => ({...p, idPhoto: url}))} imageSrc={formData.idPhoto} />
            <div style={{...styles.formGroup, background: colors.offWhite, padding: '1rem', borderRadius: '4px', display: 'flex', gap: '0.5rem'}}>
                <input type="checkbox" name="receivedCareInstructions" checked={formData.receivedCareInstructions} onChange={handleInputChange} required />
