const App = () => {
  const [appMode, setAppMode] = useState<'customer' | 'employee'>('customer');
  const [view, setView] = useState('menu');
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [savedForms, setSavedForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // --- Data Sync Logic ---
  useEffect(() => {
    const fetchForms = async () => {
        if (supabase) {
            const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: true });
            if (!error && data) {
                setSavedForms(data.map(item => ({ ...item.form_data, id: item.id })));
            }
        } else {
            const stored = localStorage.getItem('tattooConsentForms');
            if (stored) setSavedForms(JSON.parse(stored));
        }
        setLoading(false);
    };
    fetchForms();

    // Subscribe to real-time updates if Supabase is available
    let subscription: any = null;
    if (supabase) {
        subscription = supabase.channel('schema-db-changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, payload => {
                fetchForms();
            }).subscribe();
    }

    return () => { if (subscription) supabase?.removeChannel(subscription); };
  }, []);

  const handleAddForm = async (formData, formType) => {
    const newForm = { 
        ...formData, 
        submissionDate: new Date().toLocaleString(), 
        formType,
        serviceCategory: formData.serviceCategory || (formType === 'tattoo' ? 'tattoo' : 'piercing')
    };

    if (supabase) {
        const { error } = await supabase.from('consent_forms').insert([{ 
            form_data: newForm, 
            service_category: newForm.serviceCategory,
            form_type: formType
        }]);
        if (error) {
            alert('Cloud sync failed, saving locally.');
            saveLocally(newForm);
        }
    } else {
        saveLocally(newForm);
    }
    setView('success');
  };

  const saveLocally = (form) => {
      const updated = [...savedForms, { ...form, id: Date.now() }];
      setSavedForms(updated);
      localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
  };

  const handleRemove = async (id) => {
      if (supabase && typeof id === 'string') {
          await supabase.from('consent_forms').delete().eq('id', id);
      } else {
          const updated = savedForms.filter(f => f.id !== id);
          setSavedForms(updated);
          localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
      }
  };

  return (
    <div style={styles.appContainer}>
        {loading ? (
            <div style={{flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.primaryPink}}>Loading...</div>
        ) : appMode === 'customer' ? (
            <div style={styles.kioskContainer}>
                {view !== 'success' && (
                    <header style={styles.header}>
                        <h1 style={styles.logoText}>THE Pink Elephant</h1>
                        <div style={styles.logoSubText}>Piercing & Tattoo Parlor</div>
                    </header>
                )}
                {view === 'menu' && (
                    <div style={styles.formSelectionMenu}>
                        <p style={{textAlign: 'center', marginBottom: '1rem', color: colors.darkGray}}>Welcome! Select a form to begin:</p>
                        <button onClick={() => setView('tattoo')} style={{...styles.button, ...styles.menuButton}}><span>Tattoo Consent</span><span>→</span></button>
                        <button onClick={() => setView('piercing')} style={{...styles.button, ...styles.menuButton}}><span>Piercing Consent</span><span>→</span></button>
                        <button onClick={() => setView('minor')} style={{...styles.button, ...styles.menuButton}}><span>Minor (Under 18)</span><span>→</span></button>
                    </div>
                )}
                {view === 'tattoo' && <TattooConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'piercing' && <PiercingConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'minor' && <MinorConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'success' && (
                    <div style={styles.successMessage}>
                        <span style={styles.successIcon}>✓</span>
                        <h2 style={{...styles.h2, border: 'none'}}>Success!</h2>
                        <p>Your form is submitted. Please take a seat, we'll call you shortly!</p>
                        <button onClick={() => setView('menu')} style={styles.button}>New Form</button>
                    </div>
                )}
                <footer style={styles.footer}><button onClick={() => setShowStaffLogin(true)} style={styles.staffLink}>Staff Access</button></footer>
            </div>
        ) : (
            <EmployeeDashboard forms={savedForms} onRemove={handleRemove} onLogout={() => setAppMode('customer')} />
        )}

        {showStaffLogin && (
            <div style={styles.modalBackdrop}>
                <div style={{...styles.modalContent, width: '320px', textAlign: 'center'}}>
                    <h2 style={{...styles.h2, border: 'none', marginTop: 0}}>Staff Login</h2>
                    <input type="password" placeholder="Passcode" autoFocus style={{...styles.input, textAlign: 'center'}} onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                            if ((e.target as HTMLInputElement).value === 'PINK') {
                                setAppMode('employee'); setShowStaffLogin(false);
                            } else { alert('Wrong passcode'); }
                        }
                    }} />
                    <button onClick={() => setShowStaffLogin(false)} style={{...styles.button, ...styles.buttonSecondary, marginTop: '1rem', width: '100%', margin: 0}}>Cancel</button>
                </div>
            </div>
        )}
    </div>
  );
};

createRoot(document.getElementById('root')!).render(<App />);

