const App = () => {
  const [appMode, setAppMode] = useState<'customer' | 'employee'>('customer');
  const [view, setView] = useState('menu');
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [savedForms, setSavedForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // --- Real-time Data Handling ---
  useEffect(() => {
    const fetchForms = async () => {
        if (supabase) {
            const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: true });
            if (!error && data) {
                setSavedForms(data.map(item => ({ ...item.form_data, id: item.id })));
            }
        } else {
            const stored = localStorage.getItem('tattooConsentForms');
            if (stored) setSavedForms(JSON.parse(stored));
        }
        setLoading(false);
    };
    fetchForms();

    let subscription: any = null;
    if (supabase) {
        subscription = supabase.channel('queue-updates')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, payload => {
                fetchForms();
            }).subscribe();
    }

    return () => { if (subscription) supabase?.removeChannel(subscription); };
  }, []);

  const handleAddForm = async (formData, formType) => {
    const now = new Date();
    const newForm = { 
        ...formData, 
        submissionDate: now.toLocaleDateString(),
        submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        formType,
        serviceCategory: formData.serviceCategory || (formType === 'tattoo' ? 'tattoo' : 'piercing')
    };

    if (supabase) {
        const { error } = await supabase.from('consent_forms').insert([{ 
            form_data: newForm, 
            service_category: newForm.serviceCategory,
            form_type: formType
        }]);
        if (error) {
            console.error('Supabase error:', error);
            saveLocally(newForm);
        }
    } else {
        saveLocally(newForm);
    }
    setView('success');
  };

  const saveLocally = (form) => {
      const updated = [...savedForms, { ...form, id: Date.now() }];
      setSavedForms(updated);
      localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
  };

  const handleRemove = async (id) => {
      if (supabase && typeof id === 'number' === false) { // Supabase IDs are usually strings or UUIDs
          await supabase.from('consent_forms').delete().eq('id', id);
      } else {
          // Local fallback deletion
          const updated = savedForms.filter(f => f.id !== id);
          setSavedForms(updated);
          localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
      }
  };

  return (
    <div style={styles.appContainer}>
        {loading ? (
            <div style={{flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.primaryPink, fontSize: '1.5rem', fontWeight: '900'}}>
                LOADING PARLOR APP...
            </div>
        ) : appMode === 'customer' ? (
            <div style={styles.kioskContainer}>
                {view !== 'success' && (
                    <header style={styles.header}>
                        <h1 style={styles.logoText}>THE Pink Elephant</h1>
                        <div style={styles.logoSubText}>Tattoo & Piercing Parlor</div>
                    </header>
                )}
                {view === 'menu' && (
                    <div style={styles.formSelectionMenu}>
                        <p style={{textAlign: 'center', marginBottom: '1.5rem', color: colors.darkGray, fontSize: '1.1rem', fontWeight: '500'}}>Ready for your session? Fill out your consent form below:</p>
                        <button onClick={() => setView('tattoo')} style={styles.menuButton}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
