const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = getCanvasContext();
      if (ctx) {
        ctx.strokeStyle = colors.textColor;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
      }
    }
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    let clientX = e.clientX;
    let clientY = e.clientY;
    if (e.touches && e.touches.length > 0) {
        clientX = e.touches[0].clientX;
        clientY = e.touches[0].clientY;
    }
    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY,
    };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath();
    ctx.moveTo(x, y);
    setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const stopDrawing = (e) => {
    if (e && e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    ctx.closePath();
    setIsDrawing(false);
    if (canvasRef.current) {
        onSignatureChange(canvasRef.current.toDataURL());
    }
  };

  const clearSignature = () => {
    const ctx = getCanvasContext();
    if (!ctx || !canvasRef.current) return;
    ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    onSignatureChange('');
  };

  useImperativeHandle(ref, () => ({ clear: clearSignature }));

  return (
    <div style={{ position: 'relative' }}>
      <canvas
        ref={canvasRef}
        width="800"
        height="250"
        style={styles.signatureCanvas}
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
      />
      <div style={{ marginTop: '0.75rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Draw your signature above</span>
        <button type="button" onClick={clearSignature} style={{...styles.button, ...styles.buttonSecondary, padding: '0.5rem 1rem', fontSize: '0.85rem'}}>Clear</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
    };

    useEffect(() => {
        if (isCameraOpen) {
            const startCamera = async () => {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ 
                        video: { facingMode: 'environment' } 
                    });
                    streamRef.current = stream;
                    if (videoRef.current) videoRef.current.srcObject = stream;
                } catch (err) {
                    try {
                        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
                        streamRef.current = stream;
                        if (videoRef.current) videoRef.current.srcObject = stream;
                    } catch (fallbackErr) {
                        alert("Could not access the camera.");
                        setIsCameraOpen(false);
                    }
                }
            };
            startCamera();
        } else {
            stopStream();
        }
        return () => stopStream();
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas && video.readyState >= 3) {
            const context = canvas.getContext('2d');
            if (context) {
                canvas.width = video.videoWidth;
                canvas.height = video.videoHeight;
                context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
                onImageUpload(canvas.toDataURL('image/jpeg'));
                setIsCameraOpen(false);
            }
        }
    };

    return (
        <div style={styles.formGroup}>
            <label style={styles.label}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, ...styles.buttonSecondary, width: '100%', border: `2px dashed ${colors.mediumGray}`, background: 'transparent' }}>
                    📷 Open Camera to Scan ID
                </button>
            ) : (
                <div style={{ marginTop: '0.5rem', display: 'flex', alignItems: 'center', gap: '1.5rem', padding: '1rem', backgroundColor: colors.offWhite, borderRadius: '8px', border: `1px solid ${colors.lightGray}` }}>
                    <img src={imageSrc} alt="Preview" style={{ maxWidth: '120px', maxHeight: '120px', borderRadius: '4px', border: `1px solid ${colors.lightGray}`, objectFit: 'cover' }} />
                    <div>
                        <p style={{ margin: '0 0 0.5rem 0', fontWeight: '600', fontSize: '0.85rem' }}>ID Captured Successfully</p>
                        <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, ...styles.buttonDanger, padding: '0.4rem 0.8rem', fontSize: '0.8rem', margin: 0 }}>Retake</button>
                    </div>
                </div>
            )}
            {isCameraOpen && (
                <div style={styles.modalBackdrop}>
                    <div style={{...styles.modalContent, width: '600px'}}>
                         <div style={styles.modalHeader}>
                            <h2 style={{...styles.h2, marginTop: 0, border: 'none'}}>Scan ID Card</h2>
                            <button onClick={() => setIsCameraOpen(false)} style={styles.closeButton}>&times;</button>
                        </div>
                        <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '12px', background: '#000' }}>
                            <video ref={videoRef} autoPlay playsInline style={{ width: '100%', display: 'block' }}></video>
                            <div style={{ position: 'absolute', top: '20%', left: '10%', right: '10%', bottom: '20%', border: '2px solid rgba(255,255,255,0.5)', borderRadius: '8px', pointerEvents: 'none' }}></div>
                        </div>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ textAlign: 'center', marginTop: '1.5rem', display: 'flex', gap: '1rem', justifyContent: 'center' }}>
                            <button type="button" onClick={capturePhoto} style={{...styles.button, padding: '1rem 3rem'}}>CAPTURE PHOTO</button>
                            <button type="button" onClick={() => setIsCameraOpen(false)} style={{...styles.button, ...styles.buttonSecondary}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

