const App = () => {
  const [appMode, setAppMode] = useState<'customer' | 'employee'>('customer');
  const [view, setView] = useState('menu');
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [savedForms, setSavedForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // --- Data & Real-time Sync ---
  const fetchForms = async () => {
    if (supabase) {
        const { data, error } = await supabase
            .from('consent_forms')
            .select('*')
            .order('created_at', { ascending: true });
        if (!error && data) {
            setSavedForms(data.map(item => ({ ...item.form_data, id: item.id })));
        }
    } else {
        const stored = localStorage.getItem('tattooConsentForms');
        if (stored) setSavedForms(JSON.parse(stored));
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchForms();

    let subscription: any = null;
    if (supabase) {
        subscription = supabase.channel('queue-updates')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, () => {
                fetchForms();
            }).subscribe();
    }

    return () => { if (subscription) supabase?.removeChannel(subscription); };
  }, []);

  const handleAddForm = async (formData, formType) => {
    const now = new Date();
    const serviceCategory = formData.serviceCategory || (formType === 'tattoo' ? 'tattoo' : 'piercing');
    const newForm = { 
        ...formData, 
        submissionDate: now.toLocaleDateString(),
        submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        formType,
        serviceCategory
    };

    if (supabase) {
        const { error } = await supabase.from('consent_forms').insert([{ 
            form_data: newForm, 
            service_category: serviceCategory,
            form_type: formType
        }]);
        if (error) {
            console.error('Supabase insert error:', error);
            saveLocally(newForm);
        }
    } else {
        saveLocally(newForm);
    }
    setView('success');
  };

  const saveLocally = (form) => {
      const updated = [...savedForms, { ...form, id: Date.now() }];
      setSavedForms(updated);
      localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
  };

  const handleRemove = async (id) => {
      // Logic for deleting from Supabase or LocalStorage
      if (supabase && isNaN(Number(id))) { 
          await supabase.from('consent_forms').delete().eq('id', id);
      } else {
          const updated = savedForms.filter(f => f.id !== id);
          setSavedForms(updated);
          localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
      }
      // Re-fetch to ensure sync
      fetchForms();
  };

  return (
    <div style={styles.appContainer}>
        {loading ? (
            <div style={{flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.primaryPink, fontSize: '1.5rem', fontWeight: '900'}}>
                LOADING PARLOR APP...
            </div>
        ) : appMode === 'customer' ? (
            <div style={styles.kioskContainer}>
                {view !== 'success' && (
                    <header style={styles.header}>
                        <h1 style={styles.logoText}>THE Pink Elephant</h1>
                        <div style={styles.logoSubText}>Tattoo & Piercing Parlor</div>
                    </header>
                )}
                {view === 'menu' && (
                    <div style={styles.formSelectionMenu}>
                        <p style={{textAlign: 'center', marginBottom: '1.5rem', color: colors.darkGray, fontSize: '1.1rem', fontWeight: '500'}}>Ready for your session? Fill out your consent form below:</p>
                        <button onClick={() => setView('tattoo')} style={styles.menuButton}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                <span style={{ fontSize: '2rem' }}>🎨</span>
                                <span>TATTOO CONSENT</span>
                            </div>
                            <span style={{ color: colors.primaryPink }}>→</span>
                        </button>
                        <button onClick={() => setView('piercing')} style={{...styles.menuButton, borderColor: colors.purple}}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                <span style={{ fontSize: '2rem' }}>💎</span>
                                <span>PIERCING CONSENT</span>
                            </div>
                            <span style={{ color: colors.purple }}>→</span>
                        </button>
                        <button onClick={() => setView('minor')} style={{...styles.menuButton, borderColor: '#F59E0B'}}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                <span style={{ fontSize: '2rem' }}>👶</span>
                                <span>MINOR CONSENT</span>
                            </div>
                            <span style={{ color: '#F59E0B' }}>→</span>
                        </button>
                        <div style={{marginTop: '2rem', textAlign: 'center'}}>
                            <button onClick={() => setShowStaffLogin(true)} style={styles.staffLink}>Staff Dashboard Access</button>
                        </div>
                    </div>
                )}
                {view === 'tattoo' && <TattooConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'piercing' && <PiercingConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'minor' && <MinorConsentForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'success' && (
                    <div style={styles.successMessage}>
                        <span style={styles.successIcon}>✓</span>
                        <h2 style={{...styles.h2, border: 'none'}}>Success!</h2>
                        <p>Your consent form has been submitted and you've been added to the queue.</p>
                        <p>Please wait for an artist to call your name.</p>
                        <button onClick={() => setView('menu')} style={{...styles.button, marginTop: '2rem'}}>BACK TO HOME</button>
                    </div>
                )}
            </div>
        ) : (
            <EmployeeDashboard forms={savedForms} onRemove={handleRemove} onLogout={() => { setAppMode('customer'); setView('menu'); }} />
        )}

        {showStaffLogin && (
            <div style={styles.modalBackdrop}>
                <div style={{...styles.modalContent, width: '350px', textAlign: 'center'}}>
                    <h2 style={{...styles.h2, border: 'none', marginTop: 0}}>Artist Access</h2>
                    <p style={{ fontSize: '0.85rem', color: colors.mediumGray, marginBottom: '1rem' }}>Enter studio passcode to view queue</p>
                    <input type="password" placeholder="Passcode" autoFocus style={{...styles.input, textAlign: 'center'}} onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                            if ((e.target as HTMLInputElement).value === 'PINK') {
                                setAppMode('employee'); setShowStaffLogin(false);
                            } else { alert('Incorrect Passcode'); }
                        }
                    }} />
                    <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                        <button onClick={() => setShowStaffLogin(false)} style={{...styles.button, ...styles.buttonSecondary, flex: 1, margin: 0}}>CANCEL</button>
                        <button onClick={() => {
                            const input = document.querySelector('input[type="password"]') as HTMLInputElement;
                            if (input.value === 'PINK') { setAppMode('employee'); setShowStaffLogin(false); } else { alert('Incorrect Passcode'); }
                        }} style={{...styles.button, flex: 1, margin: 0}}>LOGIN</button>
                    </div>
                </div>
            </div>
        )}

        <footer style={styles.footer}>
            &copy; {new Date().getFullYear()} The Pink Elephant. All Rights Reserved.
        </footer>
    </div>
  );
};

