const QueueItem = ({ form, idx, accentColor, onRemove, onView }) => {
    const [waitTime, setWaitTime] = useState('');

    useEffect(() => {
        const calculate = () => {
            const start = new Date(form.timestamp || Date.now()).getTime();
            const now = Date.now();
            const diff = Math.floor((now - start) / 60000);
            setWaitTime(diff > 0 ? `${diff}m` : 'Just now');
        };
        calculate();
        const interval = setInterval(calculate, 30000);
        return () => clearInterval(interval);
    }, [form.timestamp]);

    return (
        <li style={{...styles.queueItem, borderLeft: idx === 0 ? `8px solid ${accentColor}` : styles.queueItem.border}}>
            {idx === 0 && <span style={{fontSize: '0.7rem', color: accentColor, fontWeight: '900', textTransform: 'uppercase', marginBottom: '0.2rem', display: 'block'}}>Next Up</span>}
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start'}}>
                <div style={styles.queueItemName}>{form.fullName || form.minorName}</div>
                <span style={styles.badgeWaiting}>{waitTime}</span>
            </div>
            <div style={styles.queueItemSub}>
                <div style={{display: 'flex', gap: '0.4rem'}}>
                    <span style={getBadgeStyle(form.formType)}>{form.formType}</span>
                    {form.minorName && <span style={getBadgeStyle('minor')}>Minor</span>}
                </div>
                <span style={{opacity: 0.6}}>Submitted {form.submissionTime}</span>
            </div>
            <div style={styles.queueActions}>
                <button onClick={() => onView(form)} style={{...styles.button, ...styles.buttonBlue, fontSize: '0.8rem', padding: '0.4rem 0.8rem', flex: 1}}>VIEW</button>
                <button onClick={() => onRemove(form.id)} style={{...styles.button, ...styles.buttonDanger, fontSize: '0.8rem', padding: '0.4rem 0.8rem', flex: 1}}>DONE</button>
            </div>
        </li>
    );
};

