// --- Custom Components ---

const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const ctx = getCanvasContext();
    if (ctx) {
      ctx.strokeStyle = colors.textColor;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
    }
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    let clientX = e.clientX || (e.touches && e.touches[0].clientX);
    let clientY = e.clientY || (e.touches && e.touches[0].clientY);
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath(); ctx.moveTo(x, y); setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y); ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    getCanvasContext()?.closePath();
    setIsDrawing(false);
    if (canvasRef.current) onSignatureChange(canvasRef.current.toDataURL());
  };

  useImperativeHandle(ref, () => ({ 
    clear: () => {
      const ctx = getCanvasContext();
      if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      onSignatureChange('');
    }
  }));

  return (
    <div style={{ position: 'relative' }}>
      <canvas ref={canvasRef} width="800" height="250" style={styles.signatureCanvas}
        onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} />
      <div style={{ marginTop: '0.5rem', display: 'flex', justifyContent: 'space-between' }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Sign above</span>
        <button type="button" onClick={() => (ref as any).current.clear()} style={{...styles.button, ...styles.buttonSecondary, padding: '0.4rem 0.8rem', fontSize: '0.8rem'}}>Clear</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopCamera = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        setIsCameraOpen(false);
    };

    // Initialize camera once modal is open and video element is rendered
    useEffect(() => {
        if (isCameraOpen && videoRef.current) {
            const initCamera = async () => {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ 
                        video: { facingMode: 'environment' } 
                    });
                    streamRef.current = stream;
                    if (videoRef.current) {
                        videoRef.current.srcObject = stream;
                    }
                } catch (err) {
                    console.error("Camera access error:", err);
                    alert("Unable to access camera. Please check your browser permissions.");
                    setIsCameraOpen(false);
                }
            };
            initCamera();
        }
        return () => {
            if (streamRef.current) {
                streamRef.current.getTracks().forEach(track => track.stop());
            }
        };
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas) {
            canvas.width = video.videoWidth; 
            canvas.height = video.videoHeight;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.drawImage(video, 0, 0);
                onImageUpload(canvas.toDataURL('image/jpeg'));
                stopCamera();
            }
        }
    };

    return (
        <div style={styles.formGroup}>
            <label style={styles.label}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, ...styles.buttonSecondary, width: '100%', border: `2px dashed ${colors.mediumGray}`, background: 'transparent' }}>
                    📷 Scan ID Card
                </button>
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '1rem', background: colors.offWhite, borderRadius: '8px' }}>
                    <img src={imageSrc} style={{ maxWidth: '100px', borderRadius: '4px', border: `1px solid ${colors.lightGray}` }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, ...styles.buttonDanger, padding: '0.4rem 0.8rem', fontSize: '0.8rem' }}>Retake</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={styles.modalBackdrop}>
                    <div style={{...styles.modalContent, width: '90%', maxWidth: '500px'}}>
                        <h3 style={{marginTop: 0}}>Scan Document</h3>
                        <video 
                            ref={videoRef} 
                            autoPlay 
                            playsInline 
                            muted
                            style={{ width: '100%', borderRadius: '8px', backgroundColor: '#000', minHeight: '300px' }}
                        ></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                            <button onClick={capturePhoto} style={{...styles.button, flex: 1}}>CAPTURE</button>
                            <button onClick={stopCamera} style={{...styles.button, ...styles.buttonSecondary, flex: 1}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

// --- Dashboard Logic ---

const QueueItem = ({ form, idx, accentColor, onRemove, onView }) => {
    const [waitTime, setWaitTime] = useState('');

    useEffect(() => {
        const calculate = () => {
            const start = new Date(form.timestamp || Date.now()).getTime();
            const now = Date.now();
            const diff = Math.floor((now - start) / 60000);
            setWaitTime(diff > 0 ? `${diff}m` : 'Just now');
        };
        calculate();
        const interval = setInterval(calculate, 30000);
        return () => clearInterval(interval);
    }, [form.timestamp]);

    return (
        <li style={{...styles.queueItem, borderLeft: idx === 0 ? `8px solid ${accentColor}` : styles.queueItem.border}}>
            {idx === 0 && <span style={{fontSize: '0.7rem', color: accentColor, fontWeight: '900', textTransform: 'uppercase', marginBottom: '0.2rem', display: 'block'}}>Next Up</span>}
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start'}}>
                <div style={styles.queueItemName}>{form.fullName || form.minorName}</div>
                <span style={styles.badgeWaiting}>{waitTime}</span>
            </div>
            <div style={styles.queueItemSub}>
                <div style={{display: 'flex', gap: '0.4rem'}}>
                    <span style={getBadgeStyle(form.formType)}>{form.formType}</span>
                    {form.minorName && <span style={getBadgeStyle('minor')}>Minor</span>}
                </div>
                <span style={{opacity: 0.6}}>Submitted {form.submissionTime}</span>
            </div>
            <div style={styles.queueActions}>
                <button onClick={() => onView(form)} style={{...styles.button, ...styles.buttonBlue, fontSize: '0.8rem', padding: '0.4rem 0.8rem', flex: 1}}>VIEW</button>
                <button onClick={() => onRemove(form.id)} style={{...styles.button, ...styles.buttonDanger, fontSize: '0.8rem', padding: '0.4rem 0.8rem', flex: 1}}>DONE</button>
            </div>
        </li>
    );
};

