                    <div style={{display: 'flex', gap: '0.5rem', marginTop: '1.5rem'}}>
                        <button onClick={() => setShowStaffLogin(false)} style={{...styles.buttonSecondary, flex: 1}}>CANCEL</button>
                        <button onClick={() => {
                            const val = (document.querySelector('input[type="password"]') as any)?.value;
                            if (val === 'PINK') { setAppMode('employee'); setShowStaffLogin(false); }
                            else alert('Invalid passcode');
                        }} style={{...styles.button, flex: 1}}>LOGIN</button>
                    </div>
                </div>
            </div>
        )}

        <footer style={{marginTop: 'auto', textAlign: 'center', padding: '2rem', color: colors.mediumGray, fontSize: '0.8rem'}}>
            &copy; {new Date().getFullYear()} The Pink Elephant. All Rights Reserved.
        </footer>
    </div>
  );
};

