// --- Main App ---

const App = () => {
  const [appMode, setAppMode] = useState<'customer' | 'employee'>('customer');
  const [employeeSubMode, setEmployeeSubMode] = useState<'selection' | 'dashboard'>('selection');
  const [activeQueue, setActiveQueue] = useState<'tattoo' | 'piercing' | null>(null);
  const [view, setView] = useState('menu');
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [savedForms, setSavedForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewingForm, setViewingForm] = useState<any>(null);

  const fetchForms = async () => {
    if (supabase) {
        const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: true });
        if (!error && data) setSavedForms(data.map(item => ({ ...item.form_data, id: item.id, timestamp: item.created_at })));
    } else {
        const stored = localStorage.getItem('tattooConsentForms');
        if (stored) setSavedForms(JSON.parse(stored));
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchForms();
    if (supabase) {
        const sub = supabase.channel('queue').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchForms).subscribe();
        return () => { supabase.removeChannel(sub); };
    }
  }, []);

  const handleAddForm = async (formData, formType) => {
    const now = new Date();
    const service = formData.serviceCategory || (formType === 'tattoo' ? 'tattoo' : 'piercing');
    const newForm = { 
        ...formData, 
        submissionDate: now.toLocaleDateString(),
        submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        formType, serviceCategory: service, timestamp: now.toISOString()
    };

    if (supabase) {
        await supabase.from('consent_forms').insert([{ form_data: newForm, service_category: service, form_type: formType }]);
    } else {
        const updated = [...savedForms, { ...newForm, id: Date.now(), timestamp: now.toISOString() }];
        setSavedForms(updated);
        localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
    }
    setView('success');
  };

  const handleRemove = async (id) => {
    if (supabase && isNaN(Number(id))) await supabase.from('consent_forms').delete().eq('id', id);
    else {
        const updated = savedForms.filter(f => f.id !== id);
        setSavedForms(updated);
        localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
    }
    fetchForms();
  };

  const logoutEmployee = () => {
      setAppMode('customer');
      setEmployeeSubMode('selection');
      setActiveQueue(null);
  };

  const filteredForms = activeQueue ? savedForms.filter(f => f.serviceCategory === activeQueue) : [];

  return (
    <div style={styles.appContainer}>
        {loading ? <div style={{flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center'}}>Loading Parlor...</div> : 
        appMode === 'customer' ? (
            <div style={styles.kioskContainer}>
                {view !== 'success' && (
                    <header style={styles.header}>
                        <h1 style={styles.logoText}>THE Pink Elephant</h1>
                        <div style={styles.logoSubText}>Tattoo & Piercing Parlor</div>
                    </header>
                )}
                {view === 'menu' && (
                    <div style={{display: 'flex', flexDirection: 'column', gap: '1rem', maxWidth: '500px', margin: '0 auto'}}>
                        <button onClick={() => setView('tattoo')} style={styles.menuButton}><span>🎨 TATTOO CONSENT</span><span>→</span></button>
                        <button onClick={() => setView('piercing')} style={{...styles.menuButton, borderColor: colors.purple}}><span>💎 PIERCING CONSENT</span><span>→</span></button>
                        <button onClick={() => setView('minor')} style={{...styles.menuButton, borderColor: '#F59E0B'}}><span>👶 MINOR CONSENT</span><span>→</span></button>
                        <button onClick={() => setShowStaffLogin(true)} style={styles.staffLink}>Staff Access</button>
                    </div>
                )}
                {view === 'tattoo' && <TattooForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'piercing' && <PiercingForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'minor' && <MinorForm onSubmit={handleAddForm} onBack={() => setView('menu')} />}
                {view === 'success' && (
                    <div style={styles.successMessage}>
                        <span style={styles.successIcon}>✓</span>
                        <h2>Submission Successful</h2>
                        <p>We've added you to the artist's queue. We'll call you shortly!</p>
                        <button onClick={() => setView('menu')} style={{...styles.button, marginTop: '2rem'}}>START NEW FORM</button>
                    </div>
                )}
            </div>
        ) : (
            <>
                {employeeSubMode === 'selection' ? (
                    <div style={styles.deptSelectorCard}>
                        <h2 style={{marginBottom: '2rem'}}>Select Department</h2>
                        <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                            <button onClick={() => { setActiveQueue('tattoo'); setEmployeeSubMode('dashboard'); }} style={{...styles.menuButton, height: '100px'}}>
