                            </button>
                            <button onClick={logoutEmployee} style={{...styles.buttonSecondary, marginTop: '1rem'}}>LOGOUT</button>
                        </div>
                    </div>
                ) : (
                    <div style={styles.dashboardContainer}>
                        <header style={styles.dashboardHeader}>
                            <div>
                                <h2 style={{margin: 0, color: activeQueue === 'tattoo' ? colors.primaryPink : colors.purple}}>
