const QueueItem = ({ form, idx, accentColor, onRemove, onView, isHistory = false }) => {
    const [waitTime, setWaitTime] = useState('');

    useEffect(() => {
        if (isHistory) return;
        const calculate = () => {
            const start = new Date(form.timestamp || Date.now()).getTime();
            const now = Date.now();
            const diff = Math.floor((now - start) / 60000);
            setWaitTime(diff > 0 ? `${diff}m` : 'Just now');
        };
        calculate();
        const interval = setInterval(calculate, 30000);
        return () => clearInterval(interval);
    }, [form.timestamp, isHistory]);

    return (
        <li style={{...styles.queueItem, borderLeft: (!isHistory && idx === 0) ? `8px solid ${accentColor}` : styles.queueItem.border}}>
            {(!isHistory && idx === 0) && <span style={{fontSize: '0.7rem', color: accentColor, fontWeight: '900', textTransform: 'uppercase', marginBottom: '0.2rem', display: 'block'}}>Next Up</span>}
