const App = () => {
  const [appMode, setAppMode] = useState<'customer' | 'employee'>('customer');
  const [employeeSubMode, setEmployeeSubMode] = useState<'selection' | 'dashboard'>('selection');
  const [dashboardTab, setDashboardTab] = useState<'queue' | 'history'>('queue');
  const [activeQueue, setActiveQueue] = useState<'tattoo' | 'piercing' | null>(null);
  const [view, setView] = useState('menu');
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [allForms, setAllForms] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewingForm, setViewingForm] = useState<any>(null);
  const [isCloudSyncing, setIsCloudSyncing] = useState(!!supabase);
  const [searchQuery, setSearchQuery] = useState('');

  const fetchForms = async () => {
    if (supabase) {
        const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: false });
        if (!error && data) {
            setAllForms(data.map(item => ({ ...item.form_data, id: item.id, timestamp: item.created_at, db_status: 'archived' })));
            setIsCloudSyncing(true);
        } else {
            console.error("Supabase error:", error);
            setIsCloudSyncing(false);
            loadLocalData();
        }
    } else {
        setIsCloudSyncing(false);
        loadLocalData();
    }
    setLoading(false);
  };

  const loadLocalData = () => {
      const stored = localStorage.getItem('tattooConsentForms');
      if (stored) setAllForms(JSON.parse(stored));
  };

  useEffect(() => {
    fetchForms();
    if (supabase) {
        const sub = supabase.channel('queue').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchForms).subscribe();
        return () => { supabase.removeChannel(sub); };
    }
  }, []);

  const handleAddForm = async (formData, formType) => {
    const now = new Date();
    const service = formData.serviceCategory || (formType === 'tattoo' ? 'tattoo' : 'piercing');
    const newForm = { 
        ...formData, 
        submissionDate: now.toLocaleDateString(),
        submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        formType, serviceCategory: service, timestamp: now.toISOString(),
        isDone: false
    };

    if (supabase) {
        try {
            const { error } = await supabase.from('consent_forms').insert([{ form_data: newForm, service_category: service, form_type: formType }]);
            if (error) throw error;
        } catch (e) {
            saveLocal(newForm, now);
        }
    } else {
        saveLocal(newForm, now);
    }
    setView('success');
  };

  const saveLocal = (newForm, now) => {
      const updated = [...allForms, { ...newForm, id: Date.now(), timestamp: now.toISOString() }];
      setAllForms(updated);
      localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
  };

  const handleRemove = async (id) => {
    const isSupabaseId = typeof id === 'string' && id.includes('-');

    // Instead of actual deletion, we update form_data.isDone to true in cloud storage
    // If the SQL schema doesn't support updates yet, we just remove from active list in memory
    // For this prototype, let's stick to true deletion to clear the artist's screen
    if (supabase && isSupabaseId) {
        const { error } = await supabase.from('consent_forms').delete().eq('id', id);
        if (error) console.error("Cloud remove failed:", error);
    } else {
        const updated = allForms.filter(f => f.id !== id);
        setAllForms(updated);
        localStorage.setItem('tattooConsentForms', JSON.stringify(updated));
    }
    fetchForms();
  };

  const logoutEmployee = () => {
      setAppMode('customer');
      setEmployeeSubMode('selection');
      setActiveQueue(null);
  };

  const activeClients = activeQueue ? allForms.filter(f => f.serviceCategory === activeQueue) : [];
  const searchResults = activeQueue ? allForms.filter(f => 
      f.serviceCategory === activeQueue && 
      (f.fullName?.toLowerCase().includes(searchQuery.toLowerCase()) || 
       f.minorName?.toLowerCase().includes(searchQuery.toLowerCase()))
  ) : [];

  return (
    <div style={styles.appContainer}>
        {loading ? <div style={{flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center'}}>Syncing with Cloud...</div> : 
        appMode === 'customer' ? (
            <div style={styles.kioskContainer}>
                {view !== 'success' && (
