                            <span style={{fontSize: '0.7rem', opacity: 0.5}}>STAFF COMMAND</span>
                        </div>

                        <button 
                            onClick={() => setStaffSubMode('queue')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'queue' ? styles.sidebarItemActive : {})}}
                        >
                            📋 LIVE QUEUE
                        </button>
                        <button 
                            onClick={() => setStaffSubMode('history')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'history' ? styles.sidebarItemActive : {})}}
                        >
                            📂 ARCHIVE SEARCH
                        </button>
                        <button 
                            onClick={() => setStaffSubMode('analytics')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'analytics' ? styles.sidebarItemActive : {})}}
