                            📊 PERFORMANCE
                        </button>

                        <div style={{marginTop: 'auto'}}>
                            <div style={{padding: '1rem', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', marginBottom: '1rem'}}>
                                <span style={{fontSize: '0.7rem', display: 'block', marginBottom: '0.3rem'}}>CONNECTION</span>
                                <span style={{fontSize: '0.8rem', color: supabase ? colors.successGreen : colors.warningAmber}}>
                                    ● {supabase ? 'Cloud Synchronized' : 'Offline / Local'}
                                </span>
                            </div>
                            <button onClick={() => setMode('kiosk')} style={{...styles.sidebarItem, color: colors.dangerRed}}>
                                🔒 LOCK & EXIT
                            </button>
                        </div>
                    </aside>

                    <main style={styles.mainContent}>
                        <div style={styles.statsGrid}>
                            <StatCard label="Live Waiting" value={stats.totalWaiting} />
                            <StatCard label="Tattoos Today" value={stats.tattoos} color={colors.primaryPink} />
                            <StatCard label="Piercings Today" value={stats.piercings} color={colors.purple} />
                            <StatCard label="Studio Daily Total" value={stats.todayCount} color={colors.textColor} />
                        </div>

                        {staffSubMode === 'queue' && (
                            <>
                                <div style={styles.sectionTitle}>
                                    Live Client Queue
                                    <input 
                                        placeholder="Search by name..." 
                                        style={{...styles.input, maxWidth: '300px', padding: '0.5rem'}} 
                                        onChange={e => setSearch(e.target.value)}
                                    />
                                </div>
                                <div style={styles.queueGrid}>
                                    {filteredQueue.map((client, i) => (
                                        <div 
