const ConsentForm = ({ type, onSubmit, onBack }) => {
    const [data, setData] = useState({ fullName: '', phone: '', email: '', signature: '', idPhoto: '', minorName: '', parentGuardianName: '', guardianIdPhoto: '', adultSignature: '', minorSignature: '' });
    const isMinor = type === 'minor';

    const handleSubmit = (e) => {
        e.preventDefault();
        if (isMinor) {
            if (!data.guardianIdPhoto || !data.adultSignature) return alert('Guardian ID and Signature required');
        } else {
            if (!data.idPhoto || !data.signature) return alert('Photo ID and Signature required');
        }
        onSubmit(data, type);
    };

    return (
        <form onSubmit={handleSubmit} style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
            <h2 style={{color: type === 'tattoo' ? colors.primaryPink : type === 'piercing' ? colors.purple : colors.warningAmber, marginBottom: '1.5rem'}}>
                {type.toUpperCase()} CONSENT FORM
            </h2>

            {isMinor ? (
                <>
                    <div style={{display: 'flex', gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Guardian Name</label><input required style={styles.input} onChange={e => setData({...data, parentGuardianName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Minor Name</label><input required style={styles.input} onChange={e => setData({...data, minorName: e.target.value})} /></div>
                    </div>
                    <ImageUploader label="Guardian Photo ID" onImageUpload={img => setData({...data, guardianIdPhoto: img})} imageSrc={data.guardianIdPhoto} />
                    <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem'}}>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Guardian Signature</label><SignaturePad onSignatureChange={s => setData({...data, adultSignature: s})} /></div>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Minor Signature</label><SignaturePad onSignatureChange={s => setData({...data, minorSignature: s})} /></div>
                    </div>
                </>
            ) : (
                <>
                    <div style={{display: 'flex', gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Full Name</label><input required style={styles.input} onChange={e => setData({...data, fullName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Phone Number</label><input required type="tel" style={styles.input} onChange={e => setData({...data, phone: e.target.value})} /></div>
                    </div>
                    <ImageUploader label="Photo ID (Driver's License / Passport)" onImageUpload={img => setData({...data, idPhoto: img})} imageSrc={data.idPhoto} />
                    <label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Signature</label>
                    <SignaturePad onSignatureChange={s => setData({...data, signature: s})} />
                </>
            )}

            <div style={{marginTop: '2rem', display: 'flex', gap: '1rem'}}>
                <button type="button" onClick={onBack} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                <button type="submit" style={{...styles.button, ...styles.primaryBtn, flex: 2}}>SUBMIT CONSENT</button>
            </div>
        </form>
    );
};

