const App = () => {
    const [mode, setMode] = useState<'kiosk' | 'staff'>('kiosk');
    const [staffSubMode, setStaffSubMode] = useState<'queue' | 'history' | 'analytics'>('queue');
    const [view, setView] = useState('menu');
    const [allForms, setAllForms] = useState<any[]>([]);
    const [viewingClient, setViewingClient] = useState<any>(null);
    const [passcodeModal, setPasscodeModal] = useState(false);
    const [search, setSearch] = useState('');

    const fetchAll = async () => {
        if (supabase) {
            const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: false });
            if (!error && data) setAllForms(data.map(d => ({ ...d.form_data, id: d.id, db_id: d.id, timestamp: d.created_at })));
        } else {
            const stored = localStorage.getItem('elep_forms');
            if (stored) setAllForms(JSON.parse(stored));
        }
    };

    useEffect(() => {
        fetchAll();
        if (supabase) {
            const sub = supabase.channel('realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchAll).subscribe();
            return () => { supabase.removeChannel(sub); };
        }
    }, []);

    const handleSubmission = async (formData, type) => {
        const now = new Date();
        const entry = {
            ...formData,
            id: Date.now().toString(),
            type,
            submissionDate: now.toLocaleDateString(),
            submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            timestamp: now.toISOString(),
            isArchived: false
        };

        if (supabase) {
            await supabase.from('consent_forms').insert([{ 
                form_data: entry, 
                service_category: type, 
                form_type: type 
            }]);
        } else {
            const updated = [entry, ...allForms];
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        setView('success');
    };

    const toggleArchived = async (client) => {
        if (supabase) {
            // In this specific schema, "Removing from queue" means deleting or marking. 
            // For simplicity, let's delete to keep the live queue fresh.
            await supabase.from('consent_forms').delete().eq('id', client.db_id);
        } else {
            const updated = allForms.filter(f => f.id !== client.id);
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        fetchAll();
    };

    const stats = useMemo(() => {
        const today = new Date().toLocaleDateString();
        const formsToday = allForms.filter(f => new Date(f.timestamp).toLocaleDateString() === today);
        return {
            totalWaiting: allForms.length,
            todayCount: formsToday.length,
            tattoos: formsToday.filter(f => f.type === 'tattoo').length,
            piercings: formsToday.filter(f => f.type === 'piercing').length
        };
    }, [allForms]);

    const filteredQueue = allForms.filter(f => 
        (f.fullName?.toLowerCase().includes(search.toLowerCase()) || f.minorName?.toLowerCase().includes(search.toLowerCase()))
    );

    return (
        <div style={styles.appContainer}>
            {mode === 'staff' ? (
                // --- STAFF PORTAL ---
                <>
                    <aside style={styles.sidebar}>
                        <div style={{marginBottom: '2.5rem', textAlign: 'center'}}>
                            <h2 style={{color: colors.primaryPink, margin: 0, fontSize: '1.2rem', letterSpacing: '2px'}}>ELEPHANT</h2>
                            <span style={{fontSize: '0.7rem', opacity: 0.5}}>STAFF COMMAND</span>
                        </div>

                        <button 
                            onClick={() => setStaffSubMode('queue')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'queue' ? styles.sidebarItemActive : {})}}
                        >
                            📋 LIVE QUEUE
                        </button>
                        <button 
                            onClick={() => setStaffSubMode('history')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'history' ? styles.sidebarItemActive : {})}}
                        >
                            📂 ARCHIVE SEARCH
                        </button>
                        <button 
                            onClick={() => setStaffSubMode('analytics')} 
                            style={{...styles.sidebarItem, ...(staffSubMode === 'analytics' ? styles.sidebarItemActive : {})}}
                        >
                            📊 PERFORMANCE
                        </button>

                        <div style={{marginTop: 'auto'}}>
                            <div style={{padding: '1rem', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', marginBottom: '1rem'}}>
                                <span style={{fontSize: '0.7rem', display: 'block', marginBottom: '0.3rem'}}>CONNECTION</span>
                                <span style={{fontSize: '0.8rem', color: supabase ? colors.successGreen : colors.warningAmber}}>
                                    ● {supabase ? 'Cloud Synchronized' : 'Offline / Local'}
                                </span>
                            </div>
                            <button onClick={() => setMode('kiosk')} style={{...styles.sidebarItem, color: colors.dangerRed}}>
                                🔒 LOCK & EXIT
                            </button>
                        </div>
                    </aside>

                    <main style={styles.mainContent}>
                        <div style={styles.statsGrid}>
                            <StatCard label="Live Waiting" value={stats.totalWaiting} />
                            <StatCard label="Tattoos Today" value={stats.tattoos} color={colors.primaryPink} />
                            <StatCard label="Piercings Today" value={stats.piercings} color={colors.purple} />
                            <StatCard label="Studio Daily Total" value={stats.todayCount} color={colors.textColor} />
                        </div>

                        {staffSubMode === 'queue' && (
                            <>
                                <div style={styles.sectionTitle}>
                                    Live Client Queue
                                    <input 
                                        placeholder="Search by name..." 
                                        style={{...styles.input, maxWidth: '300px', padding: '0.5rem'}} 
                                        onChange={e => setSearch(e.target.value)}
                                    />
                                </div>
                                <div style={styles.queueGrid}>
                                    {filteredQueue.map((client, i) => (
                                        <div 
                                            key={client.id} 
