                                                ...styles.clientCard, 
                                                borderTop: `4px solid ${client.type === 'tattoo' ? colors.primaryPink : client.type === 'piercing' ? colors.purple : colors.warningAmber}`
                                            }}
                                            onClick={() => setViewingClient(client)}
