                                            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '0.8rem'}}>
                                                <span style={{fontWeight: '900', fontSize: '1.1rem'}}>{client.fullName || client.minorName}</span>
                                                <span style={{fontSize: '0.75rem', color: colors.mediumGray}}>{client.submissionTime}</span>
                                            </div>
                                            <div style={{display: 'flex', gap: '0.5rem', marginBottom: '1rem'}}>
                                                <span style={{...styles.badge, backgroundColor: client.type === 'tattoo' ? colors.secondaryPink : client.type === 'piercing' ? colors.purpleLight : '#FEF3C7', color: client.type === 'tattoo' ? colors.primaryPink : client.type === 'piercing' ? colors.purple : colors.warningAmber}}>
                                                    {client.type}
