                                            </div>
                                            <div style={{display: 'flex', gap: '0.5rem'}}>
                                                <button onClick={(e) => { e.stopPropagation(); setViewingClient(client); }} style={{...styles.button, flex: 1, padding: '0.5rem', fontSize: '0.8rem', backgroundColor: colors.offWhite, border: `1px solid ${colors.lightGray}`}}>OPEN FILE</button>
                                                <button onClick={(e) => { e.stopPropagation(); toggleArchived(client); }} style={{...styles.button, ...styles.primaryBtn, flex: 1, padding: '0.5rem', fontSize: '0.8rem'}}>CALL NOW</button>
                                            </div>
                                        </div>
                                    ))}
