                                <p>Search past consent forms by date, name, or phone number.</p>
                                <input placeholder="Enter client name or phone..." style={{...styles.input, maxWidth: '400px'}} />
                            </div>
                        )}

                        {staffSubMode === 'analytics' && (
                            <div style={{textAlign: 'center', padding: '5rem', color: colors.mediumGray}}>
                                <h3>Analytics Module</h3>
                                <p>Revenue tracking and artist performance metrics coming soon.</p>
                            </div>
                        )}
                    </main>
                </>
            ) : (
                // --- KIOSK MODE ---
                <div style={styles.kioskContainer}>
                    <header style={{textAlign: 'center', marginBottom: '2rem'}}>
                        <h1 style={{margin: 0, fontSize: '3.5rem', color: colors.primaryPink, fontWeight: '900', letterSpacing: '4px'}}>THE PINK ELEPHANT</h1>
