const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const ctx = getCanvasContext();
    if (ctx) {
      ctx.strokeStyle = colors.textColor;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
    }
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    let clientX = e.clientX || (e.touches && e.touches[0].clientX);
    let clientY = e.clientY || (e.touches && e.touches[0].clientY);
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath(); ctx.moveTo(x, y); setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y); ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    getCanvasContext()?.closePath();
    setIsDrawing(false);
    if (canvasRef.current) onSignatureChange(canvasRef.current.toDataURL());
  };

  useImperativeHandle(ref, () => ({ 
    clear: () => {
      const ctx = getCanvasContext();
      if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      onSignatureChange('');
    }
  }));

  return (
    <div style={{ position: 'relative' }}>
      <canvas ref={canvasRef} width="800" height="250" style={{...styles.input, height: '180px', cursor: 'crosshair', padding: 0, touchAction: 'none'}}
        onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} />
      <div style={{ marginTop: '0.5rem', display: 'flex', justifyContent: 'space-between' }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Sign above</span>
        <button type="button" onClick={() => (ref as any).current.clear()} style={{...styles.button, backgroundColor: colors.lightGray, color: colors.darkGray, padding: '0.4rem 0.8rem', fontSize: '0.8rem'}}>Clear</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopCamera = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        setIsCameraOpen(false);
    };

    useEffect(() => {
        if (isCameraOpen) {
            const initCamera = async () => {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
                    streamRef.current = stream;
                    if (videoRef.current) {
                        videoRef.current.srcObject = stream;
                        await videoRef.current.play();
                    }
                } catch (err) {
                    console.error("Camera access error:", err);
                    alert("Camera blocked or unavailable.");
                    stopCamera();
                }
            };
            initCamera();
        }
        return stopCamera;
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas) {
            canvas.width = video.videoWidth; 
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0);
            onImageUpload(canvas.toDataURL('image/jpeg'));
            stopCamera();
        }
    };

    return (
        <div style={{marginBottom: '1.5rem'}}>
            <label style={{fontSize: '0.9rem', fontWeight: '600', display: 'block', marginBottom: '0.5rem'}}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, border: `2px dashed ${colors.mediumGray}`, background: 'transparent', color: colors.mediumGray, width: '100%' }}>
                    📷 Scan Document / ID
                </button>
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '1rem', background: colors.offWhite, borderRadius: '8px', border: `1px solid ${colors.lightGray}` }}>
                    <img src={imageSrc} style={{ maxWidth: '80px', borderRadius: '4px' }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, backgroundColor: colors.dangerRed, color: colors.white, padding: '0.4rem 0.8rem', fontSize: '0.8rem' }}>Delete & Retake</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={{...styles.modalBackdrop, zIndex: 2000}}>
                    <div style={{...styles.modalContent, width: '90%', maxWidth: '500px'}}>
                        <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', borderRadius: '12px', backgroundColor: '#000' }}></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                            <button onClick={capturePhoto} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>CAPTURE</button>
                            <button onClick={stopCamera} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

