const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const ctx = getCanvasContext();
    if (ctx) {
      ctx.strokeStyle = colors.textColor;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
    }
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    let clientX = e.clientX || (e.touches && e.touches[0].clientX);
    let clientY = e.clientY || (e.touches && e.touches[0].clientY);
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath(); ctx.moveTo(x, y); setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y); ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    getCanvasContext()?.closePath();
    setIsDrawing(false);
    if (canvasRef.current) onSignatureChange(canvasRef.current.toDataURL());
  };

  useImperativeHandle(ref, () => ({ 
    clear: () => {
      const ctx = getCanvasContext();
      if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      onSignatureChange('');
    }
  }));

  return (
    <div style={{ position: 'relative' }}>
      <canvas ref={canvasRef} width="800" height="250" style={{...styles.input, height: '180px', cursor: 'crosshair', padding: 0, touchAction: 'none', backgroundColor: '#fff'}}
        onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} />
      <div style={{ marginTop: '0.5rem', display: 'flex', justifyContent: 'space-between' }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Sign above</span>
        <button type="button" onClick={() => (ref as any).current.clear()} style={{...styles.button, backgroundColor: colors.lightGray, color: colors.darkGray, padding: '0.4rem 0.8rem', fontSize: '0.8rem'}}>Clear</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopCamera = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        setIsCameraOpen(false);
    };

    useEffect(() => {
        if (isCameraOpen) {
            const initCamera = async () => {
                try {
                    const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
                    streamRef.current = stream;
                    if (videoRef.current) {
                        videoRef.current.srcObject = stream;
                        await videoRef.current.play();
                    }
                } catch (err) {
                    console.error("Camera access error:", err);
                    alert("Camera blocked or unavailable.");
                    stopCamera();
                }
            };
            initCamera();
        }
        return stopCamera;
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas) {
            canvas.width = video.videoWidth; 
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0);
            onImageUpload(canvas.toDataURL('image/jpeg'));
            stopCamera();
        }
    };

    return (
        <div style={{marginBottom: '1.5rem'}}>
            <label style={{fontSize: '0.9rem', fontWeight: '600', display: 'block', marginBottom: '0.5rem'}}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, border: `2px dashed ${colors.mediumGray}`, background: 'transparent', color: colors.mediumGray, width: '100%' }}>
                    📷 Scan Document / ID
                </button>
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '1rem', background: colors.offWhite, borderRadius: '8px', border: `1px solid ${colors.lightGray}` }}>
                    <img src={imageSrc} style={{ maxWidth: '80px', borderRadius: '4px' }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, backgroundColor: colors.dangerRed, color: colors.white, padding: '0.4rem 0.8rem', fontSize: '0.8rem' }}>Delete & Retake</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={{...styles.modalBackdrop, zIndex: 2000}}>
                    <div style={{...styles.modalContent, width: '90%', maxWidth: '500px'}}>
                        <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', borderRadius: '12px', backgroundColor: '#000' }}></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                            <button onClick={capturePhoto} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>CAPTURE</button>
                            <button onClick={stopCamera} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

// --- Form Views ---

const ConsentForm = ({ type, onSubmit, onBack }) => {
    const [data, setData] = useState({ fullName: '', phone: '', email: '', signature: '', idPhoto: '', minorName: '', parentGuardianName: '', guardianIdPhoto: '', adultSignature: '', minorSignature: '' });
    const isMinor = type === 'minor';

    const handleSubmit = (e) => {
        e.preventDefault();
        if (isMinor) {
            if (!data.guardianIdPhoto || !data.adultSignature) return alert('Guardian ID and Signature required');
        } else {
            if (!data.idPhoto || !data.signature) return alert('Photo ID and Signature required');
        }
        onSubmit(data, type);
    };

    return (
        <form onSubmit={handleSubmit} style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
            <h2 style={{color: type === 'tattoo' ? colors.primaryPink : type === 'piercing' ? colors.purple : colors.warningAmber, marginBottom: '1.5rem'}}>
                {type.toUpperCase()} CONSENT FORM
            </h2>

            {isMinor ? (
                <>
                    <div style={{display: 'flex', gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Guardian Name</label><input required value={data.parentGuardianName} style={styles.input} onChange={e => setData({...data, parentGuardianName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Minor Name</label><input required value={data.minorName} style={styles.input} onChange={e => setData({...data, minorName: e.target.value})} /></div>
                    </div>
                    <ImageUploader label="Guardian Photo ID" onImageUpload={img => setData({...data, guardianIdPhoto: img})} imageSrc={data.guardianIdPhoto} />
                    <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem'}}>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Guardian Signature</label><SignaturePad onSignatureChange={s => setData({...data, adultSignature: s})} /></div>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Minor Signature</label><SignaturePad onSignatureChange={s => setData({...data, minorSignature: s})} /></div>
                    </div>
                </>
            ) : (
                <>
                    <div style={{display: 'flex', gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Full Name</label><input required value={data.fullName} style={styles.input} onChange={e => setData({...data, fullName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Phone Number</label><input required type="tel" value={data.phone} style={styles.input} onChange={e => setData({...data, phone: e.target.value})} /></div>
                    </div>
                    <ImageUploader label="Photo ID (Driver's License / Passport)" onImageUpload={img => setData({...data, idPhoto: img})} imageSrc={data.idPhoto} />
                    <label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Signature</label>
                    <SignaturePad onSignatureChange={s => setData({...data, signature: s})} />
                </>
            )}

            <div style={{marginTop: '2rem', display: 'flex', gap: '1rem'}}>
                <button type="button" onClick={onBack} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                <button type="submit" style={{...styles.button, ...styles.primaryBtn, flex: 2}}>SUBMIT CONSENT</button>
            </div>
        </form>
    );
};

// --- Main App ---

const App = () => {
    const [mode, setMode] = useState<'kiosk' | 'staff'>('kiosk');
    const [staffSubMode, setStaffSubMode] = useState<'queue' | 'history' | 'analytics' | 'settings'>('queue');
    const [view, setView] = useState('menu');
    const [allForms, setAllForms] = useState<any[]>([]);
    const [viewingClient, setViewingClient] = useState<any>(null);
    const [passcodeModal, setPasscodeModal] = useState(false);
    const [passcodeInput, setPasscodeInput] = useState('');
    const [search, setSearch] = useState('');
    const [isCloudSyncing, setIsCloudSyncing] = useState(!!supabase);

    // Supabase config state
    const [dbUrl, setDbUrl] = useState(localStorage.getItem('supabase_url') || CONFIG_URL);
    const [dbKey, setDbKey] = useState(localStorage.getItem('supabase_anon_key') || CONFIG_KEY);

    const fetchAll = async () => {
        if (supabase) {
            try {
                const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: false });
                if (!error && data) {
                    setAllForms(data.map(d => ({ ...d.form_data, id: d.id, db_id: d.id, timestamp: d.created_at })));
                    setIsCloudSyncing(true);
                } else {
                    console.error("Fetch error:", error);
                    setIsCloudSyncing(false);
                    loadLocal();
                }
            } catch (e) {
                setIsCloudSyncing(false);
                loadLocal();
            }
        } else {
            setIsCloudSyncing(false);
            loadLocal();
        }
    };

    const loadLocal = () => {
        const stored = localStorage.getItem('elep_forms');
        if (stored) setAllForms(JSON.parse(stored));
    };

    useEffect(() => {
        fetchAll();
        if (supabase) {
            const sub = supabase.channel('realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchAll).subscribe();
            return () => { supabase.removeChannel(sub); };
        }
    }, [isCloudSyncing]);

    const handleSubmission = async (formData, type) => {
        const now = new Date();
        const entry = {
            ...formData,
            id: Date.now().toString(),
            type,
            submissionDate: now.toLocaleDateString(),
            submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            timestamp: now.toISOString(),
            isArchived: false
        };

        if (supabase) {
            const { error } = await supabase.from('consent_forms').insert([{ 
                form_data: entry, 
                service_category: type, 
                form_type: type 
            }]);
            if (error) {
                console.error("Cloud insert error, falling back to local:", error);
                const updated = [entry, ...allForms];
                setAllForms(updated);
                localStorage.setItem('elep_forms', JSON.stringify(updated));
            }
        } else {
            const updated = [entry, ...allForms];
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        setView('success');
    };

    const toggleArchived = async (client) => {
        if (supabase) {
            await supabase.from('consent_forms').delete().eq('id', client.db_id);
        } else {
            const updated = allForms.filter(f => f.id !== client.id);
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        fetchAll();
    };

    const saveSettings = () => {
        localStorage.setItem('supabase_url', dbUrl);
        localStorage.setItem('supabase_anon_key', dbKey);

        if (dbUrl && dbKey) {
            try {
                supabase = createClient(dbUrl, dbKey);
                setIsCloudSyncing(true);
                alert("Settings saved! Checking connection...");
                fetchAll();
            } catch (e) {
                alert("Invalid URL or Key format.");
            }
        } else {
            supabase = null;
            setIsCloudSyncing(false);
            alert("Credentials cleared. Switching to local mode.");
        }
    };

    const stats = useMemo(() => {
        const today = new Date().toLocaleDateString();
        const formsToday = allForms.filter(f => new Date(f.timestamp).toLocaleDateString() === today);
        return {
            totalWaiting: allForms.length,
            todayCount: formsToday.length,
            tattoos: formsToday.filter(f => f.type === 'tattoo').length,
            piercings: formsToday.filter(f => f.type === 'piercing').length
        };
    }, [allForms]);

    const filteredQueue = allForms.filter(f => 
        (f.fullName?.toLowerCase().includes(search.toLowerCase()) || f.minorName?.toLowerCase().includes(search.toLowerCase()))
    );

    const handleLogin = () => {
        if (passcodeInput === 'PINK') {
            setMode('staff');
            setPasscodeModal(false);
            setPasscodeInput('');
        } else {
            alert('Access Denied');
        }
    };

    return (
        <div style={styles.appContainer}>
            {mode === 'staff' ? (
                <>
                    <aside style={styles.sidebar}>
                        <div style={{marginBottom: '2.5rem', textAlign: 'center'}}>
                            <h2 style={{color: colors.primaryPink, margin: 0, fontSize: '1.2rem', letterSpacing: '2px'}}>ELEPHANT</h2>
                            <span style={{fontSize: '0.7rem', opacity: 0.5}}>STAFF COMMAND</span>
                        </div>

                        <button onClick={() => setStaffSubMode('queue')} style={{...styles.sidebarItem, ...(staffSubMode === 'queue' ? styles.sidebarItemActive : {})}}>📋 LIVE QUEUE</button>
                        <button onClick={() => setStaffSubMode('history')} style={{...styles.sidebarItem, ...(staffSubMode === 'history' ? styles.sidebarItemActive : {})}}>📂 ARCHIVE SEARCH</button>
                        <button onClick={() => setStaffSubMode('analytics')} style={{...styles.sidebarItem, ...(staffSubMode === 'analytics' ? styles.sidebarItemActive : {})}}>📊 PERFORMANCE</button>
                        <button onClick={() => setStaffSubMode('settings')} style={{...styles.sidebarItem, ...(staffSubMode === 'settings' ? styles.sidebarItemActive : {})}}>⚙️ SYSTEM SETTINGS</button>

                        <div style={{marginTop: 'auto'}}>
                            <div style={{padding: '1rem', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', marginBottom: '1rem'}}>
                                <span style={{fontSize: '0.7rem', display: 'block', marginBottom: '0.3rem'}}>CONNECTION</span>
                                <span style={{fontSize: '0.8rem', color: isCloudSyncing ? colors.successGreen : colors.warningAmber}}>
                                    ● {isCloudSyncing ? 'Cloud Synced' : 'Offline / Local'}
                                </span>
                            </div>
                            <button onClick={() => setMode('kiosk')} style={{...styles.sidebarItem, color: colors.dangerRed}}>🔒 LOCK & EXIT</button>
                        </div>
                    </aside>

                    <main style={styles.mainContent}>
                        {staffSubMode !== 'settings' && (
                            <div style={styles.statsGrid}>
                                <StatCard label="Live Waiting" value={stats.totalWaiting} />
                                <StatCard label="Tattoos Today" value={stats.tattoos} color={colors.primaryPink} />
                                <StatCard label="Piercings Today" value={stats.piercings} color={colors.purple} />
                                <StatCard label="Studio Daily Total" value={stats.todayCount} color={colors.textColor} />
                            </div>
                        )}

                        {staffSubMode === 'queue' && (
                            <>
                                <div style={styles.sectionTitle}>
                                    Live Client Queue
                                    <input placeholder="Search by name..." value={search} style={{...styles.input, maxWidth: '300px', padding: '0.5rem'}} onChange={e => setSearch(e.target.value)} />
                                </div>
                                <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '1.5rem'}}>
                                    {filteredQueue.map((client) => (
                                        <div key={client.id} style={{...styles.clientCard, borderTop: `4px solid ${client.type === 'tattoo' ? colors.primaryPink : client.type === 'piercing' ? colors.purple : colors.warningAmber}`}} onClick={() => setViewingClient(client)}>
                                            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '0.8rem'}}>
                                                <span style={{fontWeight: '900', fontSize: '1.1rem'}}>{client.fullName || client.minorName}</span>
                                                <span style={{fontSize: '0.75rem', color: colors.mediumGray}}>{client.submissionTime}</span>
                                            </div>
                                            <div style={{display: 'flex', gap: '0.5rem', marginBottom: '1rem'}}>
                                                <span style={{padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.7rem', fontWeight: 'bold', textTransform: 'uppercase', backgroundColor: client.type === 'tattoo' ? colors.secondaryPink : client.type === 'piercing' ? colors.purpleLight : '#FEF3C7', color: client.type === 'tattoo' ? colors.primaryPink : client.type === 'piercing' ? colors.purple : colors.warningAmber}}>
                                                    {client.type}
                                                </span>
                                            </div>
                                            <div style={{display: 'flex', gap: '0.5rem'}}>
                                                <button onClick={(e) => { e.stopPropagation(); setViewingClient(client); }} style={{...styles.button, flex: 1, padding: '0.5rem', fontSize: '0.8rem', backgroundColor: colors.offWhite, border: `1px solid ${colors.lightGray}`, color: colors.textColor}}>OPEN FILE</button>
                                                <button onClick={(e) => { e.stopPropagation(); toggleArchived(client); }} style={{...styles.button, ...styles.primaryBtn, flex: 1, padding: '0.5rem', fontSize: '0.8rem'}}>CALL NOW</button>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredQueue.length === 0 && <div style={{gridColumn: '1/-1', textAlign: 'center', padding: '5rem', color: colors.mediumGray}}>No clients currently in the queue.</div>}
                                </div>
                            </>
                        )}

                        {staffSubMode === 'settings' && (
                            <div style={{maxWidth: '600px', margin: '0 auto', background: colors.white, padding: '2.5rem', borderRadius: '16px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)'}}>
                                <h2 style={{marginTop: 0, color: colors.primaryPink}}>Supabase Cloud Configuration</h2>
                                <p style={{color: colors.darkGray, marginBottom: '2rem'}}>Paste your Supabase credentials here to enable global sync across all tablets in the studio.</p>

                                <div style={{marginBottom: '1.5rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>SUPABASE URL</label>
                                    <input style={styles.input} value={dbUrl} onChange={e => setDbUrl(e.target.value)} placeholder="https://your-project.supabase.co" />
                                </div>
                                <div style={{marginBottom: '2rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>SUPABASE ANON KEY</label>
                                    <input style={styles.input} type="password" value={dbKey} onChange={e => setDbKey(e.target.value)} placeholder="your-anon-key" />
                                </div>

                                <div style={{display: 'flex', gap: '1rem'}}>
                                    <button onClick={saveSettings} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>SAVE & CONNECT</button>
                                    <button onClick={() => { setDbUrl(''); setDbKey(''); }} style={{...styles.button, backgroundColor: colors.lightGray, color: colors.darkGray}}>CLEAR</button>
                                </div>

                                <div style={{marginTop: '2rem', padding: '1rem', background: colors.offWhite, borderRadius: '8px', fontSize: '0.85rem'}}>
                                    <strong>How to find these?</strong><br/>
                                    In your Supabase Dashboard: <code>Project Settings > API</code>. Copy the Project URL and the "anon" public key.
                                </div>
                            </div>
                        )}

                        {staffSubMode === 'history' && <div style={{textAlign: 'center', padding: '5rem', color: colors.mediumGray}}><h3>Archive Database</h3><p>Cloud lookup for past records coming soon.</p></div>}
                        {staffSubMode === 'analytics' && <div style={{textAlign: 'center', padding: '5rem', color: colors.mediumGray}}><h3>Analytics</h3><p>Daily breakdown and performance stats.</p></div>}
                    </main>
                </>
            ) : (
                <div style={styles.kioskContainer}>
                    <header style={{textAlign: 'center', marginBottom: '2rem'}}>
                        <h1 style={{margin: 0, fontSize: '3.5rem', color: colors.primaryPink, fontWeight: '900', letterSpacing: '4px'}}>THE PINK ELEPHANT</h1>
                        <p style={{margin: 0, letterSpacing: '8px', color: colors.mediumGray, fontSize: '0.9rem'}}>TATTOO & PIERCING STUDIO</p>
                    </header>

                    <div style={styles.kioskCard}>
                        {view === 'menu' && (
                            <div style={{display: 'flex', flexDirection: 'column', gap: '1.5rem'}}>
                                <h3 style={{textAlign: 'center', color: colors.darkGray}}>Please Select Service</h3>
                                <button onClick={() => setView('tattoo')} style={{...styles.button, ...styles.primaryBtn, padding: '2rem', fontSize: '1.5rem', justifyContent: 'center'}}>🎨 TATTOO CONSENT</button>
                                <button onClick={() => setView('piercing')} style={{...styles.button, backgroundColor: colors.purple, color: colors.white, padding: '2rem', fontSize: '1.5rem', justifyContent: 'center'}}>💎 PIERCING CONSENT</button>
                                <button onClick={() => setView('minor')} style={{...styles.button, backgroundColor: colors.warningAmber, color: colors.white, padding: '2rem', fontSize: '1.5rem', justifyContent: 'center'}}>👶 MINOR CONSENT</button>
                                <button onClick={() => setPasscodeModal(true)} style={{marginTop: '2rem', background: 'none', border: 'none', color: colors.lightGray, cursor: 'pointer'}}>Staff Login</button>
                            </div>
