                                <h2 style={{fontSize: '2rem', margin: '1rem 0'}}>All Set!</h2>
                                <p style={{color: colors.mediumGray, fontSize: '1.2rem'}}>We've received your form. Please take a seat!</p>
                                <button onClick={() => setView('menu')} style={{...styles.button, ...styles.primaryBtn, marginTop: '2rem', padding: '1rem 3rem'}}>FINISH</button>
                            </div>
