            )}

            {passcodeModal && (
                <div style={styles.modalBackdrop}>
                    <div style={{...styles.modalContent, width: '320px', textAlign: 'center'}}>
                        <h3>Staff Access</h3>
                        <p style={{fontSize: '0.8rem', color: colors.mediumGray}}>Enter 'PINK' to enter the dashboard</p>
