                            type="password" 
                            placeholder="Passcode" 
                            autoFocus 
                            value={passcodeInput}
                            style={{...styles.input, textAlign: 'center', marginBottom: '1.5rem'}} 
                            onChange={e => setPasscodeInput(e.target.value)}
