                        />
                        <div style={{display: 'flex', gap: '0.5rem'}}>
                            <button onClick={() => { setPasscodeModal(false); setPasscodeInput(''); }} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                            <button onClick={handleLogin} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>LOGIN</button>
