                    </div>
                </div>
            )}

            {viewingClient && (
                <div style={styles.modalBackdrop} onClick={() => setViewingClient(null)}>
                    <div style={{...styles.modalContent, maxWidth: '900px', width: '95%'}} onClick={e => e.stopPropagation()}>
                        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem'}}>
                            <div>
                                <h2 style={{margin: 0}}>{viewingClient.fullName || viewingClient.minorName}</h2>
                                <span style={{fontSize: '0.8rem', color: colors.mediumGray}}>ID: {viewingClient.id} • Submitted {viewingClient.submissionDate} @ {viewingClient.submissionTime}</span>
