                            <button onClick={() => setViewingClient(null)} style={{fontSize: '2rem', background: 'none', border: 'none', cursor: 'pointer', color: colors.mediumGray}}>&times;</button>
                        </div>
                        <div style={{display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '2rem'}}>
                            <div>
                                <h4 style={{borderBottom: `2px solid ${colors.lightGray}`, paddingBottom: '0.5rem'}}>ID VERIFICATION</h4>
                                <img src={viewingClient.idPhoto || viewingClient.guardianIdPhoto} style={{width: '100%', borderRadius: '12px', border: `1px solid ${colors.lightGray}`, marginBottom: '1.5rem'}} />
                                <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem'}}>
                                    <div><strong>Phone:</strong><br/>{viewingClient.phone || 'N/A'}</div>
