                                    {viewingClient.parentGuardianName && <div style={{gridColumn: '1/-1'}}><strong>Guardian:</strong><br/>{viewingClient.parentGuardianName}</div>}
                                </div>
                            </div>
                            <div>
                                <h4 style={{borderBottom: `2px solid ${colors.lightGray}`, paddingBottom: '0.5rem'}}>SIGNATURES</h4>
                                <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                                    <div>
                                        <label style={{fontSize: '0.7rem', color: colors.mediumGray}}>PRIMARY SIGNATURE</label>
                                        <img src={viewingClient.signature || viewingClient.adultSignature} style={{width: '100%', background: colors.offWhite, border: `1px solid ${colors.lightGray}`}} />
                                    </div>
                                    {viewingClient.minorSignature && (
                                        <div>
                                            <label style={{fontSize: '0.7rem', color: colors.mediumGray}}>MINOR SIGNATURE</label>
                                            <img src={viewingClient.minorSignature} style={{width: '100%', background: colors.offWhite, border: `1px solid ${colors.lightGray}`}} />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                        <div style={{marginTop: '3rem', display: 'flex', gap: '1rem'}}>
                            <button onClick={() => setViewingClient(null)} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1, color: colors.textColor}}>BACK TO QUEUE</button>
                            <button onClick={() => { toggleArchived(viewingClient); setViewingClient(null); }} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>MARK AS COMPLETED</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

createRoot(document.getElementById('root')!).render(<App />);

