                    </div>
                    <ImageUploader label="Guardian Photo ID" onImageUpload={img => setData({...data, guardianIdPhoto: img})} imageSrc={data.guardianIdPhoto} />
                    <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem'}}>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Guardian Signature</label><SignaturePad onSignatureChange={s => setData({...data, adultSignature: s})} /></div>
                        <div><label style={{fontSize: '0.8rem', fontWeight: 'bold'}}>Minor Signature</label><SignaturePad onSignatureChange={s => setData({...data, minorSignature: s})} /></div>
