const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const resizeCanvas = () => {
      if (canvasRef.current && containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        canvasRef.current.width = rect.width;
        canvasRef.current.height = 200;
        const ctx = getCanvasContext();
        if (ctx) {
            ctx.strokeStyle = colors.textColor;
            ctx.lineWidth = 3;
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';
        }
      }
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    return () => window.removeEventListener('resize', resizeCanvas);
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX = e.clientX || (e.touches && e.touches[0].clientX);
    let clientY = e.clientY || (e.touches && e.touches[0].clientY);
    return { x: clientX - rect.left, y: clientY - rect.top };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath(); ctx.moveTo(x, y); setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y); ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    getCanvasContext()?.closePath();
    setIsDrawing(false);
    if (canvasRef.current) onSignatureChange(canvasRef.current.toDataURL());
  };

  useImperativeHandle(ref, () => ({ 
    clear: () => {
      const ctx = getCanvasContext();
      if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      onSignatureChange('');
    }
  }));

  return (
    <div ref={containerRef} style={{ position: 'relative', width: '100%' }}>
      <canvas ref={canvasRef} style={{...styles.input, height: '200px', cursor: 'crosshair', padding: 0, touchAction: 'none', backgroundColor: '#fff', border: `2px solid ${colors.lightGray}`}}
        onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} />
      <div style={{ marginTop: '0.5rem', display: 'flex', justifyContent: 'space-between' }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Sign in the box above</span>
        <button type="button" onClick={() => (ref as any).current.clear()} style={{...styles.button, backgroundColor: colors.lightGray, color: colors.darkGray, padding: '0.5rem 1rem', fontSize: '0.8rem'}}>CLEAR PAD</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc, isMobile }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
    };

    const handleClose = () => {
        stopStream();
        setIsCameraOpen(false);
    };

    useEffect(() => {
        if (isCameraOpen) {
            const initCamera = async () => {
                try {
                    const constraints = { 
                        video: { 
                            facingMode: { ideal: 'environment' },
                            width: { ideal: 1280 },
                            height: { ideal: 720 }
                        } 
                    };
                    const stream = await navigator.mediaDevices.getUserMedia(constraints);
                    streamRef.current = stream;
                    if (videoRef.current) {
                        videoRef.current.srcObject = stream;
                        await videoRef.current.play();
                    }
                } catch (err) {
                    console.error("Camera access error:", err);
                    alert("Camera blocked or unavailable. Please check permissions.");
                    handleClose();
                }
            };
            initCamera();
        }
        return stopStream;
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas) {
            canvas.width = video.videoWidth; 
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0);
            onImageUpload(canvas.toDataURL('image/jpeg'));
            handleClose();
        }
    };

    return (
        <div style={{marginBottom: '1.5rem'}}>
            <label style={{fontSize: '0.9rem', fontWeight: 'bold', display: 'block', marginBottom: '0.75rem'}}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, border: `2px dashed ${colors.mediumGray}`, background: colors.offWhite, color: colors.mediumGray, width: '100%', height: '80px' }}>
                    📸 SCAN PHOTO ID
                </button>
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '1rem', background: colors.offWhite, borderRadius: '12px', border: `1px solid ${colors.lightGray}` }}>
                    <img src={imageSrc} style={{ maxWidth: '100px', borderRadius: '8px' }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, backgroundColor: colors.dangerRed, color: colors.white, padding: '0.5rem 1rem', fontSize: '0.8rem' }}>DELETE & RETAKE</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={styles.modalBackdrop(isMobile)}>
                    <div style={{...styles.modalContent(isMobile), width: isMobile ? '100%' : '95%', maxWidth: '500px'}}>
                        <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', borderRadius: '12px', backgroundColor: '#000', minHeight: '300px', objectFit: 'cover' }}></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '1.5rem' }}>
                            <button onClick={capturePhoto} style={{...styles.button, ...styles.primaryBtn, flex: 2}}>CAPTURE PHOTO</button>
                            <button onClick={handleClose} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

