    const [staffSubMode, setStaffSubMode] = useState<'queue' | 'history' | 'analytics' | 'settings'>('queue');
    const [view, setView] = useState('menu');
    const [allForms, setAllForms] = useState<any[]>([]);
    const [viewingClient, setViewingClient] = useState<any>(null);
    const [passcodeModal, setPasscodeModal] = useState(false);
    const [passcodeInput, setPasscodeInput] = useState('');
    const [search, setSearch] = useState('');
    const [isCloudSyncing, setIsCloudSyncing] = useState(!!supabase);
    const [testStatus, setTestStatus] = useState<{message: string, success: boolean} | null>(null);

    const [dbUrl, setDbUrl] = useState(CONFIG_URL || localStorage.getItem('supabase_url') || '');
    const [dbKey, setDbKey] = useState(CONFIG_KEY || localStorage.getItem('supabase_anon_key') || '');

    const fetchAll = async () => {
        if (supabase) {
            try {
                const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: false });
                if (!error && data) {
                    setAllForms(data.map(d => ({ ...d.form_data, id: d.id, db_id: d.id, timestamp: d.created_at })));
                    setIsCloudSyncing(true);
                } else {
                    console.error("Fetch error:", error);
                    setIsCloudSyncing(false);
                    loadLocal();
                }
            } catch (e) {
                setIsCloudSyncing(false);
                loadLocal();
            }
        } else {
            setIsCloudSyncing(false);
            loadLocal();
        }
    };

    const loadLocal = () => {
        const stored = localStorage.getItem('elep_forms');
        if (stored) setAllForms(JSON.parse(stored));
    };

    useEffect(() => {
        fetchAll();
        if (supabase) {
            const sub = supabase.channel('realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchAll).subscribe();
            return () => { supabase.removeChannel(sub); };
        }
    }, [isCloudSyncing]);

    const handleSubmission = async (formData, type) => {
        const now = new Date();
        const entry = {
            ...formData,
            id: Date.now().toString(),
            type,
            submissionDate: now.toLocaleDateString(),
            submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            timestamp: now.toISOString(),
            isArchived: false
        };

        if (supabase) {
            const { error } = await supabase.from('consent_forms').insert([{ 
                form_data: entry, 
                service_category: type, 
                form_type: type 
            }]);
            if (error) {
                console.error("Cloud insert error, falling back to local:", error);
                const updated = [entry, ...allForms];
                setAllForms(updated);
                localStorage.setItem('elep_forms', JSON.stringify(updated));
            }
        } else {
            const updated = [entry, ...allForms];
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        setView('success');
    };

    const toggleArchived = async (client) => {
        if (supabase) {
            await supabase.from('consent_forms').delete().eq('id', client.db_id);
        } else {
            const updated = allForms.filter(f => f.id !== client.id);
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        fetchAll();
    };

    const testConnection = async () => {
        if (!dbUrl || !dbKey) {
            setTestStatus({message: 'Provide both URL and Key.', success: false});
            return;
        }
        try {
            const tempClient = createClient(dbUrl, dbKey);
            const { error } = await tempClient.from('consent_forms').select('id').limit(1);
            if (error) {
                setTestStatus({message: `Error: ${error.message}`, success: false});
            } else {
                setTestStatus({message: 'Connection successful!', success: true});
            }
        } catch (e) {
            setTestStatus({message: 'Failed to connect.', success: false});
        }
    };

    const saveSettings = () => {
        localStorage.setItem('supabase_url', dbUrl);
        localStorage.setItem('supabase_anon_key', dbKey);
        if (dbUrl && dbKey) {
            try {
                supabase = createClient(dbUrl, dbKey);
                setIsCloudSyncing(true);
                alert("Cloud settings saved to this device.");
                fetchAll();
            } catch (e) { alert("Invalid format."); }
        } else {
            supabase = null;
            setIsCloudSyncing(false);
            alert("Local mode activated.");
        }
    };

    const stats = useMemo(() => {
        const today = new Date().toLocaleDateString();
        const formsToday = allForms.filter(f => new Date(f.timestamp).toLocaleDateString() === today);
        return {
            totalWaiting: allForms.length,
            todayCount: formsToday.length,
            tattoos: formsToday.filter(f => f.type === 'tattoo').length,
            piercings: formsToday.filter(f => f.type === 'piercing').length
        };
    }, [allForms]);

    const filteredQueue = allForms.filter(f => 
        (f.fullName?.toLowerCase().includes(search.toLowerCase()) || f.minorName?.toLowerCase().includes(search.toLowerCase()))
    );

    const handleLogin = () => {
        if (passcodeInput.toUpperCase() === 'PINK') {
            setMode('staff');
            setPasscodeModal(false);
            setPasscodeInput('');
        } else {
            alert('Invalid Passcode');
        }
    };

    return (
        <div style={styles.appContainer(isMobile)}>
            {mode === 'staff' ? (
                <>
                    {!isMobile ? (
                        <aside style={styles.sidebar}>
                            <div style={{marginBottom: '2.5rem', textAlign: 'center'}}>
                                <h2 style={{color: colors.primaryPink, margin: 0, fontSize: '1.2rem', letterSpacing: '2px'}}>ELEPHANT</h2>
                                <span style={{fontSize: '0.7rem', opacity: 0.5}}>STAFF DASHBOARD</span>
                            </div>

                            <button onClick={() => setStaffSubMode('queue')} style={styles.sidebarItem(staffSubMode === 'queue')}>📋 LIVE QUEUE</button>
                            <button onClick={() => setStaffSubMode('history')} style={styles.sidebarItem(staffSubMode === 'history')}>📂 HISTORY</button>
                            <button onClick={() => setStaffSubMode('analytics')} style={styles.sidebarItem(staffSubMode === 'analytics')}>📊 ANALYTICS</button>
                            <button onClick={() => setStaffSubMode('settings')} style={styles.sidebarItem(staffSubMode === 'settings')}>⚙️ SYSTEM</button>

                            <div style={{marginTop: 'auto'}}>
                                <div style={{padding: '1rem', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', marginBottom: '1rem'}}>
                                    <span style={{fontSize: '0.7rem', display: 'block', marginBottom: '0.3rem'}}>STATUS</span>
                                    <span style={{fontSize: '0.8rem', color: isCloudSyncing ? colors.successGreen : colors.warningAmber}}>
                                        ● {isCloudSyncing ? 'Online Sync' : 'Local Only'}
                                    </span>
                                </div>
                                <button onClick={() => setMode('kiosk')} style={styles.sidebarItem(false)}>🔒 LOCK APP</button>
                            </div>
                        </aside>
                    ) : (
                        <nav style={styles.bottomNav}>
                            <button onClick={() => setStaffSubMode('queue')} style={styles.navItem(staffSubMode === 'queue')}><span>📋</span>QUEUE</button>
                            <button onClick={() => setStaffSubMode('history')} style={styles.navItem(staffSubMode === 'history')}><span>📂</span>HISTORY</button>
                            <button onClick={() => setStaffSubMode('settings')} style={styles.navItem(staffSubMode === 'settings')}><span>⚙️</span>SYSTEM</button>
                            <button onClick={() => setMode('kiosk')} style={styles.navItem(false)}><span>🔒</span>LOCK</button>
                        </nav>
                    )}

                    <main style={styles.mainContent(isMobile)}>
                        {staffSubMode !== 'settings' && (
                            <div style={styles.statsGrid(isMobile)}>
                                <StatCard isMobile={isMobile} label="Waiting" value={stats.totalWaiting} />
                                <StatCard isMobile={isMobile} label="Tattoos" value={stats.tattoos} color={colors.primaryPink} />
                                <StatCard isMobile={isMobile} label="Piercings" value={stats.piercings} color={colors.purple} />
                                <StatCard isMobile={isMobile} label="Today" value={stats.todayCount} color={colors.textColor} />
                            </div>
                        )}

                        {staffSubMode === 'queue' && (
                            <>
                                <div style={styles.sectionTitle}>
                                    Live Queue
                                    <input placeholder="Search..." value={search} style={{...styles.input, maxWidth: isMobile ? '100%' : '250px', padding: '0.5rem 1rem', fontSize: '0.9rem'}} onChange={e => setSearch(e.target.value)} />
                                </div>
                                <div style={{display: 'grid', gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1rem'}}>
                                    {filteredQueue.map((client) => (
                                        <div key={client.id} style={{...styles.clientCard, borderLeft: `6px solid ${client.type === 'tattoo' ? colors.primaryPink : colors.purple}`}} onClick={() => setViewingClient(client)}>
                                            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                                                <span style={{fontWeight: '900', fontSize: '1.1rem'}}>{client.fullName || client.minorName}</span>
                                                <span style={{fontSize: '0.75rem', color: colors.mediumGray}}>{client.submissionTime}</span>
                                            </div>
                                            <p style={{margin: '0.5rem 0', fontSize: '0.8rem', opacity: 0.7}}>{client.type.toUpperCase()} • {client.phone}</p>
                                            <div style={{display: 'flex', gap: '0.5rem', marginTop: '1rem'}}>
                                                <button onClick={(e) => { e.stopPropagation(); setViewingClient(client); }} style={{...styles.button, flex: 1, padding: '0.5rem', fontSize: '0.8rem', backgroundColor: colors.offWhite, color: colors.textColor}}>VIEW</button>
                                                <button onClick={(e) => { e.stopPropagation(); toggleArchived(client); }} style={{...styles.button, ...styles.primaryBtn, flex: 1, padding: '0.5rem', fontSize: '0.8rem'}}>CALL IN</button>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredQueue.length === 0 && <div style={{textAlign: 'center', padding: '3rem', color: colors.mediumGray}}>No entries found.</div>}
                                </div>
                            </>
                        )}

                        {staffSubMode === 'settings' && (
                            <div style={{maxWidth: '500px', margin: '0 auto', background: colors.white, padding: isMobile ? '1.5rem' : '2.5rem', borderRadius: '24px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)'}}>
                                <h2 style={{marginTop: 0, color: colors.primaryPink}}>Supabase Cloud Sync</h2>

                                {CONFIG_URL && (
                                    <div style={{padding: '1rem', background: colors.successGreenBg, color: colors.successGreen, borderRadius: '12px', marginBottom: '1.5rem', fontSize: '0.9rem'}}>
                                        ✨ <strong>Studio Sync Active:</strong> Your configuration is "Hardcoded". This app is automatically logged in on all tablets.
                                    </div>
                                )}

                                <div style={{marginBottom: '1.5rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>PROJECT URL</label>
                                    <input style={styles.input} value={dbUrl} onChange={e => { setDbUrl(e.target.value); setTestStatus(null); }} placeholder="https://..." />
                                </div>
                                <div style={{marginBottom: '1.5rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>ANON PUBLIC KEY</label>
                                    <input style={styles.input} type="password" value={dbKey} onChange={e => { setDbKey(e.target.value); setTestStatus(null); }} placeholder="Paste key here" />
                                </div>
                                {testStatus && (
                                    <div style={{padding: '1rem', borderRadius: '12px', marginBottom: '1.5rem', backgroundColor: testStatus.success ? colors.successGreenBg : '#FEE2E2', color: testStatus.success ? colors.successGreen : colors.dangerRed, fontSize: '0.9rem'}}>
                                        {testStatus.message}
                                    </div>
                                )}
                                <div style={{display: 'flex', gap: '1rem', flexDirection: 'column'}}>
                                    <button onClick={saveSettings} style={{...styles.button, ...styles.primaryBtn}}>SAVE TO THIS DEVICE</button>
                                    <button onClick={testConnection} style={{...styles.button, backgroundColor: colors.offWhite, border: `1px solid ${colors.mediumGray}`, color: colors.textColor}}>TEST CONNECTION</button>
                                </div>

                                <p style={{marginTop: '2rem', fontSize: '0.8rem', color: colors.mediumGray, textAlign: 'center'}}>
                                    To log in all tablets at once, edit the code and paste your keys into the CONFIG_URL and CONFIG_KEY variables at the top of index.tsx.
                                </p>
                            </div>
                        )}
                    </main>
                </>
            ) : (
                <div style={styles.kioskContainer(isMobile)}>
                    <header style={{textAlign: 'center', marginBottom: isMobile ? '1.5rem' : '3rem'}}>
                        <h1 style={{margin: 0, fontSize: isMobile ? '2rem' : '3.5rem', color: colors.primaryPink, fontWeight: '900', letterSpacing: '2px'}}>THE PINK ELEPHANT</h1>
                        <p style={{margin: 0, letterSpacing: '4px', color: colors.mediumGray, fontSize: '0.75rem'}}>TATTOO & PIERCING STUDIO</p>
                    </header>

                    <div style={styles.kioskCard(isMobile)}>
                        {view === 'menu' && (
                            <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                                <h3 style={{textAlign: 'center', color: colors.darkGray, marginBottom: '1rem'}}>Select a service to begin</h3>
                                <button onClick={() => setView('tattoo')} style={{...styles.button, ...styles.primaryBtn, padding: '2.5rem', fontSize: '1.4rem'}}>🎨 TATTOO CONSENT</button>
                                <button onClick={() => setView('piercing')} style={{...styles.button, backgroundColor: colors.purple, color: colors.white, padding: '2.5rem', fontSize: '1.4rem'}}>💎 PIERCING CONSENT</button>
                                <button onClick={() => setView('minor')} style={{...styles.button, backgroundColor: colors.warningAmber, color: colors.white, padding: '2.5rem', fontSize: '1.4rem'}}>👶 MINOR CONSENT</button>
                                <button onClick={() => setPasscodeModal(true)} style={{marginTop: '2rem', background: 'none', border: 'none', color: colors.lightGray, cursor: 'pointer', fontSize: '0.9rem'}}>Staff Login</button>
                            </div>
                        )}
                        {(view === 'tattoo' || view === 'piercing' || view === 'minor') && <ConsentForm isMobile={isMobile} type={view} onBack={() => setView('menu')} onSubmit={handleSubmission} />}
                        {view === 'success' && (
                            <div style={{textAlign: 'center', padding: isMobile ? '1rem' : '4rem'}}>
                                <div style={{fontSize: '6rem', color: colors.successGreen}}>✓</div>
                                <h2 style={{fontSize: '2rem', margin: '1rem 0', color: colors.textColor}}>Submission Received!</h2>
                                <p style={{color: colors.mediumGray, fontSize: '1.1rem'}}>Please notify your artist or wait for your name to be called.</p>
                                <button onClick={() => setView('menu')} style={{...styles.button, ...styles.primaryBtn, marginTop: '2rem', padding: '1.25rem 3rem'}}>DONE</button>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {passcodeModal && (
                <div style={styles.modalBackdrop(isMobile)}>
                    <div style={{...styles.modalContent(isMobile), width: isMobile ? '100%' : '350px', textAlign: 'center'}}>
                        <h3 style={{color: colors.textColor}}>Staff Entrance</h3>
                        <p style={{fontSize: '0.9rem', color: colors.mediumGray, marginBottom: '2rem'}}>Enter studio passcode to continue</p>
                        <input type="password" placeholder="••••" autoFocus value={passcodeInput} style={{...styles.input, textAlign: 'center', marginBottom: '1.5rem', letterSpacing: '10px'}} onChange={e => setPasscodeInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleLogin()} />
                        <div style={{display: 'flex', gap: '0.75rem'}}>
                            <button onClick={() => { setPasscodeModal(false); setPasscodeInput(''); }} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1, color: colors.textColor}}>CANCEL</button>
                            <button onClick={handleLogin} style={{...styles.button, ...styles.primaryBtn, flex: 1}}>LOGIN</button>
                        </div>
                    </div>
                </div>
            )}

            {viewingClient && (
                <div style={styles.modalBackdrop(isMobile)} onClick={() => setViewingClient(null)}>
                    <div style={styles.modalContent(isMobile)} onClick={e => e.stopPropagation()}>
                        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.5rem'}}>
                            <div>
                                <h2 style={{margin: 0, color: colors.textColor, fontSize: isMobile ? '1.5rem' : '2rem'}}>{viewingClient.fullName || viewingClient.minorName}</h2>
                                <p style={{fontSize: '0.85rem', color: colors.mediumGray, margin: '4px 0'}}>{viewingClient.submissionDate} @ {viewingClient.submissionTime}</p>
                            </div>
                            <button onClick={() => setViewingClient(null)} style={{fontSize: '2.5rem', background: 'none', border: 'none', cursor: 'pointer', color: colors.mediumGray, lineHeight: 1}}>&times;</button>
                        </div>
                        <div style={{display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1.2fr 1fr', gap: '2rem'}}>
                            <div>
                                <label style={{fontSize: '0.75rem', fontWeight: 'bold', color: colors.mediumGray, display: 'block', marginBottom: '0.5rem'}}>IDENTIFICATION PHOTO</label>
                                <img src={viewingClient.idPhoto || viewingClient.guardianIdPhoto} style={{width: '100%', borderRadius: '16px', border: `1px solid ${colors.lightGray}`, marginBottom: '1.5rem'}} />
                                <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', color: colors.textColor}}>
                                    <div><small style={{color: colors.mediumGray}}>Phone</small><br/><strong>{viewingClient.phone || 'N/A'}</strong></div>
                                    <div><small style={{color: colors.mediumGray}}>Service</small><br/><strong style={{textTransform: 'uppercase'}}>{viewingClient.type}</strong></div>
                                    {viewingClient.parentGuardianName && <div style={{gridColumn: '1/-1'}}><small style={{color: colors.mediumGray}}>Parent/Guardian</small><br/><strong>{viewingClient.parentGuardianName}</strong></div>}
                                </div>
                            </div>
                            <div>
                                <label style={{fontSize: '0.75rem', fontWeight: 'bold', color: colors.mediumGray, display: 'block', marginBottom: '0.5rem'}}>SIGNATURE(S)</label>
                                <div style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                                    <div style={{background: colors.offWhite, padding: '10px', borderRadius: '12px'}}>
                                        <small style={{color: colors.mediumGray, fontSize: '0.65rem'}}>CLIENT/GUARDIAN</small>
                                        <img src={viewingClient.signature || viewingClient.adultSignature} style={{width: '100%', mixBlendMode: 'multiply'}} />
                                    </div>
                                    {viewingClient.minorSignature && (
                                        <div style={{background: colors.offWhite, padding: '10px', borderRadius: '12px'}}>
                                            <small style={{color: colors.mediumGray, fontSize: '0.65rem'}}>MINOR SIGNATURE</small>
                                            <img src={viewingClient.minorSignature} style={{width: '100%', mixBlendMode: 'multiply'}} />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                        <div style={{marginTop: '2.5rem', display: 'flex', gap: '1rem', flexDirection: isMobile ? 'column' : 'row'}}>
                            <button onClick={() => { toggleArchived(viewingClient); setViewingClient(null); }} style={{...styles.button, ...styles.primaryBtn, flex: 2, height: '60px'}}>COMPLETE & ARCHIVE</button>
                            <button onClick={() => setViewingClient(null)} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1, color: colors.textColor, height: '60px'}}>CLOSE FILE</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

createRoot(document.getElementById('root')!).render(<App />);

import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef, useMemo } from 'react';
