// Get these from: Supabase Dashboard > Settings > API
const CONFIG_URL = ''; // e.g., 'https://your-project.supabase.co'
const CONFIG_KEY = ''; // e.g., 'eyJhbGciOiJIUzI1Ni...'

// STEP 2: Set your private staff dashboard passcode below.
const STAFF_PASSCODE = 'PINK'; 
// =====================================================================

const colors = {
    primaryPink: '#D94686',
    primaryPinkDark: '#B83A71',
    secondaryPink: '#FCE7F3',
    white: '#FFFFFF',
    offWhite: '#F9FAFB',
    lightGray: '#E5E7EB',
    mediumGray: '#9CA3AF',
    darkGray: '#4B5563',
    sidebarBg: '#111827',
    sidebarText: '#9CA3AF',
    sidebarActive: '#FFFFFF',
    textColor: '#1F2937', 
    dangerRed: '#DC2626',
    successGreen: '#10B981',
    successGreenBg: '#D1FAE5',
    warningAmber: '#F59E0B',
    blue: '#2563EB',
    purple: '#8B5CF6',
    purpleLight: '#EDE9FE',
};

const useIsMobile = () => {
    const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
    useEffect(() => {
        const handleResize = () => setIsMobile(window.innerWidth < 768);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);
    return isMobile;
};

