    marginTop: isMobile ? '0' : '2rem',
  }),
  statsGrid: (isMobile: boolean) => ({
    display: 'grid',
    gridTemplateColumns: isMobile ? '1fr 1fr' : 'repeat(auto-fit, minmax(200px, 1fr))',
