const SignaturePad = forwardRef<any, { onSignatureChange: (url: string) => void }>(({ onSignatureChange }, ref) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const getCanvasContext = () => canvasRef.current?.getContext('2d');

  useEffect(() => {
    const resizeCanvas = () => {
      if (canvasRef.current && containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        canvasRef.current.width = rect.width;
        canvasRef.current.height = 200;
        const ctx = getCanvasContext();
        if (ctx) {
            ctx.strokeStyle = colors.textColor;
            ctx.lineWidth = 3;
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';
        }
      }
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    return () => window.removeEventListener('resize', resizeCanvas);
  }, []);

  const getCoords = (e) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX = e.clientX || (e.touches && e.touches[0].clientX);
    let clientY = e.clientY || (e.touches && e.touches[0].clientY);
    return { x: clientX - rect.left, y: clientY - rect.top };
  };

  const startDrawing = (e) => {
    if (e.cancelable) e.preventDefault();
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.beginPath(); ctx.moveTo(x, y); setIsDrawing(true);
  };

  const draw = (e) => {
    if (e.cancelable) e.preventDefault();
    if (!isDrawing) return;
    const ctx = getCanvasContext();
    if (!ctx) return;
    const { x, y } = getCoords(e);
    ctx.lineTo(x, y); ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    getCanvasContext()?.closePath();
    setIsDrawing(false);
    if (canvasRef.current) onSignatureChange(canvasRef.current.toDataURL());
  };

  useImperativeHandle(ref, () => ({ 
    clear: () => {
      const ctx = getCanvasContext();
      if (ctx && canvasRef.current) ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      onSignatureChange('');
    }
  }));

  return (
    <div ref={containerRef} style={{ position: 'relative', width: '100%' }}>
      <canvas ref={canvasRef} style={{...styles.input, height: '200px', cursor: 'crosshair' as const, padding: 0, touchAction: 'none', backgroundColor: '#fff', border: `2px solid ${colors.lightGray}`}}
        onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
        onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} />
      <div style={{ marginTop: '0.5rem', display: 'flex' as const, justifyContent: 'space-between' as const }}>
        <span style={{ fontSize: '0.8rem', color: colors.mediumGray }}>Sign in the box above</span>
        <button type="button" onClick={() => (ref as any).current.clear()} style={{...styles.button, backgroundColor: colors.lightGray, color: colors.darkGray, padding: '0.5rem 1rem', fontSize: '0.8rem'}}>CLEAR PAD</button>
      </div>
    </div>
  );
});

const ImageUploader = ({ label, onImageUpload, imageSrc, isMobile }) => {
    const [isCameraOpen, setIsCameraOpen] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
    };

    const handleClose = () => {
        stopStream();
        setIsCameraOpen(false);
    };

    useEffect(() => {
        if (isCameraOpen) {
            const initCamera = async () => {
                try {
                    const constraints = { 
                        video: { 
                            facingMode: { ideal: 'environment' },
                            width: { ideal: 1280 },
                            height: { ideal: 720 }
                        } 
                    };
                    const stream = await navigator.mediaDevices.getUserMedia(constraints);
                    streamRef.current = stream;
                    if (videoRef.current) {
                        videoRef.current.srcObject = stream;
                        await videoRef.current.play();
                    }
                } catch (err) {
                    console.error("Camera access error:", err);
                    alert("Camera blocked or unavailable. Please check permissions.");
                    handleClose();
                }
            };
            initCamera();
        }
        return stopStream;
    }, [isCameraOpen]);

    const capturePhoto = () => {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas) {
            canvas.width = video.videoWidth; 
            canvas.height = video.videoHeight;
            canvas.getContext('2d')?.drawImage(video, 0, 0);
            onImageUpload(canvas.toDataURL('image/jpeg'));
            handleClose();
        }
    };

    return (
        <div style={{marginBottom: '1.5rem'}}>
            <label style={{fontSize: '0.9rem', fontWeight: 'bold', display: 'block', marginBottom: '0.75rem'}}>{label}</label>
            {!imageSrc ? (
                 <button type="button" onClick={() => setIsCameraOpen(true)} style={{ ...styles.button, border: `2px dashed ${colors.mediumGray}`, background: colors.offWhite, color: colors.mediumGray, width: '100%', height: '80px' }}>
                    📸 SCAN PHOTO ID
                </button>
            ) : (
                <div style={{ display: 'flex' as const, alignItems: 'center' as const, gap: '1rem', padding: '1rem', background: colors.offWhite, borderRadius: '12px', border: `1px solid ${colors.lightGray}` }}>
                    <img src={imageSrc} style={{ maxWidth: '100px', borderRadius: '8px' }} />
                    <button type="button" onClick={() => onImageUpload('')} style={{ ...styles.button, backgroundColor: colors.dangerRed, color: colors.white, padding: '0.5rem 1rem', fontSize: '0.8rem' }}>DELETE & RETAKE</button>
                </div>
            )}
            {isCameraOpen && (
                <div style={styles.modalBackdrop(isMobile)}>
                    <div style={{...styles.modalContent(isMobile), width: isMobile ? '100%' : '95%', maxWidth: '500px'}}>
                        <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', borderRadius: '12px', backgroundColor: '#000', minHeight: '300px', objectFit: 'cover' as const }}></video>
                        <canvas ref={canvasRef} style={{ display: 'none' }}></canvas>
                        <div style={{ display: 'flex' as const, gap: '1rem', marginTop: '1.5rem' }}>
                            <button onClick={capturePhoto} style={{...styles.button, ...styles.primaryBtn, flex: 2}}>CAPTURE PHOTO</button>
                            <button onClick={handleClose} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1}}>CANCEL</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const ConsentForm = ({ type, onSubmit, onBack, isMobile }) => {
    const [data, setData] = useState({ fullName: '', phone: '', email: '', signature: '', idPhoto: '', minorName: '', parentGuardianName: '', guardianIdPhoto: '', adultSignature: '', minorSignature: '' });
    const isMinor = type === 'minor';

    const handleSubmit = (e) => {
        e.preventDefault();
        if (isMinor) {
            if (!data.guardianIdPhoto || !data.adultSignature) return alert('Guardian ID and Signature required');
        } else {
            if (!data.idPhoto || !data.signature) return alert('Photo ID and Signature required');
        }
        onSubmit(data, type);
    };

    return (
        <form onSubmit={handleSubmit} style={{display: 'flex' as const, flexDirection: 'column' as const, gap: '1.25rem'}}>
            <h2 style={{color: type === 'tattoo' ? colors.primaryPink : type === 'piercing' ? colors.purple : colors.warningAmber, marginBottom: '0.5rem', fontSize: isMobile ? '1.5rem' : '2rem'}}>
                {type.toUpperCase()} CONSENT
            </h2>

            {isMinor ? (
                <>
                    <div style={{display: 'flex' as const, flexDirection: isMobile ? 'column' : 'row' as const, gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Guardian Name</label><input required value={data.parentGuardianName} style={styles.input} onChange={e => setData({...data, parentGuardianName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Minor Name</label><input required value={data.minorName} style={styles.input} onChange={e => setData({...data, minorName: e.target.value})} /></div>
                    </div>
                    <ImageUploader isMobile={isMobile} label="Guardian Photo ID" onImageUpload={img => setData({...data, guardianIdPhoto: img})} imageSrc={data.guardianIdPhoto} />
                    <div style={{display: 'flex' as const, flexDirection: isMobile ? 'column' : 'row' as const, gap: '1.5rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Guardian Signature</label><SignaturePad onSignatureChange={s => setData({...data, adultSignature: s})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Minor Signature</label><SignaturePad onSignatureChange={s => setData({...data, minorSignature: s})} /></div>
                    </div>
                </>
            ) : (
                <>
                    <div style={{display: 'flex' as const, flexDirection: isMobile ? 'column' : 'row' as const, gap: '1rem'}}>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Full Name</label><input required value={data.fullName} style={styles.input} onChange={e => setData({...data, fullName: e.target.value})} /></div>
                        <div style={{flex: 1}}><label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Phone Number</label><input required type="tel" value={data.phone} style={styles.input} onChange={e => setData({...data, phone: e.target.value})} /></div>
                    </div>
                    <ImageUploader isMobile={isMobile} label="Valid Photo ID" onImageUpload={img => setData({...data, idPhoto: img})} imageSrc={data.idPhoto} />
                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', color: colors.textColor}}>Your Signature</label>
                    <SignaturePad onSignatureChange={s => setData({...data, signature: s})} />
                </>
            )}

            <div style={{marginTop: '2rem', display: 'flex' as const, gap: '1rem', flexDirection: isMobile ? 'column' : 'row' as const}}>
                <button type="submit" style={{...styles.button, ...styles.primaryBtn, flex: 2, height: '60px'}}>SUBMIT FORM</button>
                <button type="button" onClick={onBack} style={{...styles.button, backgroundColor: colors.lightGray, flex: 1, color: colors.textColor, height: '60px'}}>GO BACK</button>
            </div>
        </form>
    );
};

const App = () => {
    const isMobile = useIsMobile();
    const [mode, setMode] = useState<'kiosk' | 'staff'>('kiosk');
    const [staffSubMode, setStaffSubMode] = useState<'queue' | 'history' | 'analytics' | 'settings'>('queue');
    const [view, setView] = useState('menu');
    const [allForms, setAllForms] = useState<any[]>([]);
    const [viewingClient, setViewingClient] = useState<any>(null);
    const [passcodeModal, setPasscodeModal] = useState(false);
    const [passcodeInput, setPasscodeInput] = useState('');
    const [search, setSearch] = useState('');
    const [testStatus, setTestStatus] = useState<{message: string, success: boolean} | null>(null);

    // Track if we are using the hardwired code settings or device local settings
    const [dbUrl, setDbUrl] = useState(CONFIG_URL || localStorage.getItem('supabase_url') || '');
    const [dbKey, setDbKey] = useState(CONFIG_KEY || localStorage.getItem('supabase_anon_key') || '');

    const supabase = useMemo(() => {
        if (dbUrl && dbKey) {
            try { return createClient(dbUrl, dbKey); } catch (e) { return null; }
        }
        return null;
    }, [dbUrl, dbKey]);

    const isCloudSyncing = !!supabase;

    const fetchAll = async () => {
        if (supabase) {
            try {
                const { data, error } = await supabase.from('consent_forms').select('*').order('created_at', { ascending: false });
                if (!error && data) {
                    setAllForms(data.map(d => ({ ...d.form_data, id: d.id, db_id: d.id, timestamp: d.created_at })));
                } else {
                    loadLocal();
                }
            } catch (e) {
                loadLocal();
            }
        } else {
            loadLocal();
        }
    };

    const loadLocal = () => {
        const stored = localStorage.getItem('elep_forms');
        if (stored) setAllForms(JSON.parse(stored));
    };

    useEffect(() => {
        fetchAll();
        if (supabase) {
            const sub = supabase.channel('realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'consent_forms' }, fetchAll).subscribe();
            return () => { supabase.removeChannel(sub); };
        }
    }, [supabase]);

    const handleSubmission = async (formData, type) => {
        const now = new Date();
        const entry = {
            ...formData,
            id: Date.now().toString(),
            type,
            submissionDate: now.toLocaleDateString(),
            submissionTime: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            timestamp: now.toISOString(),
            isArchived: false
        };

        if (supabase) {
            const { error } = await supabase.from('consent_forms').insert([{ 
                form_data: entry, 
                service_category: type, 
                form_type: type 
            }]);
            if (error) {
                console.error("Cloud insert error, falling back to local:", error);
                saveLocal(entry);
            }
        } else {
            saveLocal(entry);
        }
        setView('success');
    };

    const saveLocal = (entry) => {
        const updated = [entry, ...allForms];
        setAllForms(updated);
        localStorage.setItem('elep_forms', JSON.stringify(updated));
    };

    const toggleArchived = async (client) => {
        if (supabase) {
            await supabase.from('consent_forms').delete().eq('id', client.db_id);
        } else {
            const updated = allForms.filter(f => f.id !== client.id);
            setAllForms(updated);
            localStorage.setItem('elep_forms', JSON.stringify(updated));
        }
        fetchAll();
    };

    const testConnection = async () => {
        if (!dbUrl || !dbKey) {
            setTestStatus({message: 'Provide both URL and Key.', success: false});
            return;
        }
        try {
            const tempClient = createClient(dbUrl, dbKey);
            const { error } = await tempClient.from('consent_forms').select('id').limit(1);
            if (error) {
                setTestStatus({message: `Error: ${error.message}`, success: false});
            } else {
                setTestStatus({message: 'Connection successful!', success: true});
            }
        } catch (e) {
            setTestStatus({message: 'Failed to connect.', success: false});
        }
    };

    const saveSettings = () => {
        localStorage.setItem('supabase_url', dbUrl);
        localStorage.setItem('supabase_anon_key', dbKey);
        alert("Local device settings updated. Note: Hardwired keys take priority.");
        fetchAll();
    };

    const stats = useMemo(() => {
        const today = new Date().toLocaleDateString();
        const formsToday = allForms.filter(f => new Date(f.timestamp).toLocaleDateString() === today);
        return {
            totalWaiting: allForms.length,
            todayCount: formsToday.length,
            tattoos: formsToday.filter(f => f.type === 'tattoo').length,
            piercings: formsToday.filter(f => f.type === 'piercing').length
        };
    }, [allForms]);

    const filteredQueue = allForms.filter(f => 
        (f.fullName?.toLowerCase().includes(search.toLowerCase()) || f.minorName?.toLowerCase().includes(search.toLowerCase()))
    );

    const handleLogin = () => {
        if (passcodeInput.toUpperCase() === STAFF_PASSCODE.toUpperCase()) {
            setMode('staff');
            setPasscodeModal(false);
            setPasscodeInput('');
        } else {
            alert('Invalid Passcode');
        }
    };

    return (
        <div style={styles.appContainer(isMobile)}>
            {mode === 'staff' ? (
                <>
                    {!isMobile ? (
                        <aside style={styles.sidebar}>
                            <div style={{marginBottom: '2.5rem', textAlign: 'center' as const}}>
                                <h2 style={{color: colors.primaryPink, margin: 0, fontSize: '1.2rem', letterSpacing: '2px'}}>ELEPHANT</h2>
                                <span style={{fontSize: '0.7rem', opacity: 0.5}}>STAFF DASHBOARD</span>
                            </div>

                            <button onClick={() => setStaffSubMode('queue')} style={styles.sidebarItem(staffSubMode === 'queue')}>📋 LIVE QUEUE</button>
                            <button onClick={() => setStaffSubMode('history')} style={styles.sidebarItem(staffSubMode === 'history')}>📂 HISTORY</button>
                            <button onClick={() => setStaffSubMode('analytics')} style={styles.sidebarItem(staffSubMode === 'analytics')}>📊 ANALYTICS</button>
                            <button onClick={() => setStaffSubMode('settings')} style={styles.sidebarItem(staffSubMode === 'settings')}>⚙️ SYSTEM</button>

                            <div style={{marginTop: 'auto'}}>
                                <div style={{padding: '1rem', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', marginBottom: '1rem'}}>
                                    <span style={{fontSize: '0.7rem', display: 'block', marginBottom: '0.3rem'}}>STATUS</span>
                                    <span style={{fontSize: '0.8rem', color: isCloudSyncing ? colors.successGreen : colors.warningAmber}}>
                                        ● {isCloudSyncing ? (CONFIG_URL ? 'Studio Sync (Global)' : 'Device Sync (Local)') : 'Offline Mode'}
                                    </span>
                                </div>
                                <button onClick={() => setMode('kiosk')} style={styles.sidebarItem(false)}>🔒 LOCK APP</button>
                            </div>
                        </aside>
                    ) : (
                        <nav style={styles.bottomNav}>
                            <button onClick={() => setStaffSubMode('queue')} style={styles.navItem(staffSubMode === 'queue')}><span>📋</span>QUEUE</button>
                            <button onClick={() => setStaffSubMode('history')} style={styles.navItem(staffSubMode === 'history')}><span>📂</span>HISTORY</button>
                            <button onClick={() => setStaffSubMode('settings')} style={styles.navItem(staffSubMode === 'settings')}><span>⚙️</span>SYSTEM</button>
                            <button onClick={() => setMode('kiosk')} style={styles.navItem(false)}><span>🔒</span>LOCK</button>
                        </nav>
                    )}

                    <main style={styles.mainContent(isMobile)}>
                        {staffSubMode !== 'settings' && (
                            <div style={styles.statsGrid(isMobile)}>
                                <StatCard isMobile={isMobile} label="Waiting" value={stats.totalWaiting} />
                                <StatCard isMobile={isMobile} label="Tattoos" value={stats.tattoos} color={colors.primaryPink} />
                                <StatCard isMobile={isMobile} label="Piercings" value={stats.piercings} color={colors.purple} />
                                <StatCard isMobile={isMobile} label="Today" value={stats.todayCount} color={colors.textColor} />
                            </div>
                        )}

                        {staffSubMode === 'queue' && (
                            <>
                                <div style={styles.sectionTitle}>
                                    Live Queue
                                    <input placeholder="Search..." value={search} style={{...styles.input, maxWidth: isMobile ? '100%' : '250px', padding: '0.5rem 1rem', fontSize: '0.9rem'}} onChange={e => setSearch(e.target.value)} />
                                </div>
                                <div style={{display: 'grid' as const, gridTemplateColumns: isMobile ? '1fr' : 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1rem'}}>
                                    {filteredQueue.map((client) => (
                                        <div key={client.id} style={{...styles.clientCard, borderLeft: `6px solid ${client.type === 'tattoo' ? colors.primaryPink : colors.purple}`}} onClick={() => setViewingClient(client)}>
                                            <div style={{display: 'flex' as const, justifyContent: 'space-between' as const, alignItems: 'center' as const}}>
                                                <span style={{fontWeight: '900', fontSize: '1.1rem'}}>{client.fullName || client.minorName}</span>
                                                <span style={{fontSize: '0.75rem', color: colors.mediumGray}}>{client.submissionTime}</span>
                                            </div>
                                            <p style={{margin: '0.5rem 0', fontSize: '0.8rem', opacity: 0.7}}>{client.type.toUpperCase()} • {client.phone}</p>
                                            <div style={{display: 'flex' as const, gap: '0.5rem', marginTop: '1rem'}}>
                                                <button onClick={(e) => { e.stopPropagation(); setViewingClient(client); }} style={{...styles.button, flex: 1, padding: '0.5rem', fontSize: '0.8rem', backgroundColor: colors.offWhite, color: colors.textColor}}>VIEW</button>
                                                <button onClick={(e) => { e.stopPropagation(); toggleArchived(client); }} style={{...styles.button, ...styles.primaryBtn, flex: 1, padding: '0.5rem', fontSize: '0.8rem'}}>CALL IN</button>
                                            </div>
                                        </div>
                                    ))}
                                    {filteredQueue.length === 0 && <div style={{textAlign: 'center' as const, padding: '3rem', color: colors.mediumGray}}>No entries found.</div>}
                                </div>
                            </>
                        )}

                        {staffSubMode === 'settings' && (
                            <div style={{maxWidth: '500px', margin: '0 auto', background: colors.white, padding: isMobile ? '1.5rem' : '2.5rem', borderRadius: '24px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)'}}>
                                <h2 style={{marginTop: 0, color: colors.primaryPink}}>Cloud Synchronization</h2>

                                {CONFIG_URL ? (
                                    <div style={{padding: '1.25rem', background: colors.successGreenBg, color: colors.successGreen, borderRadius: '16px', marginBottom: '1.5rem', fontSize: '0.9rem', border: `1px solid ${colors.successGreen}`}}>
                                        ✨ <strong>Studio Sync Active</strong><br/>
                                        This app is hardwired to your studio database. All tablets will use these settings automatically.
                                    </div>
                                ) : (
                                    <div style={{padding: '1.25rem', background: '#FEF3C7', color: '#92400E', borderRadius: '16px', marginBottom: '1.5rem', fontSize: '0.9rem'}}>
                                        ⚠️ <strong>Device Specific Setup</strong><br/>
                                        You are currently using local device settings. Paste your keys in the code editor to log in all tablets at once.
                                    </div>
                                )}

                                <div style={{marginBottom: '1.5rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>SUPABASE URL</label>
                                    <input style={styles.input} value={dbUrl} onChange={e => { setDbUrl(e.target.value); setTestStatus(null); }} placeholder="https://your-project.supabase.co" disabled={!!CONFIG_URL} />
                                </div>
                                <div style={{marginBottom: '1.5rem'}}>
                                    <label style={{fontSize: '0.8rem', fontWeight: 'bold', display: 'block', marginBottom: '0.5rem'}}>SUPABASE ANON KEY</label>
                                    <input style={styles.input} type="password" value={dbKey} onChange={e => { setDbKey(e.target.value); setTestStatus(null); }} placeholder="Paste anon key here" disabled={!!CONFIG_URL} />
                                </div>
                                {testStatus && (
                                    <div style={{padding: '1rem', borderRadius: '12px', marginBottom: '1.5rem', backgroundColor: testStatus.success ? colors.successGreenBg : '#FEE2E2', color: testStatus.success ? colors.successGreen : colors.dangerRed, fontSize: '0.9rem'}}>
                                        {testStatus.message}
                                    </div>
                                )}
                                {!CONFIG_URL && (
                                    <div style={{display: 'flex' as const, gap: '1rem', flexDirection: 'column' as const}}>
                                        <button onClick={saveSettings} style={{...styles.button, ...styles.primaryBtn}}>SAVE TO THIS DEVICE</button>
                                        <button onClick={testConnection} style={{...styles.button, backgroundColor: colors.offWhite, border: `1px solid ${colors.mediumGray}`, color: colors.textColor}}>TEST CONNECTION</button>
                                    </div>
                                )}

                                <p style={{marginTop: '2rem', fontSize: '0.8rem', color: colors.mediumGray, textAlign: 'center' as const}}>
                                    Staff Passcode: <strong>{STAFF_PASSCODE}</strong><br/>
                                    (Can be changed in the code editor)
                                </p>
                            </div>
                        )}
                    </main>
                </>
            ) : (
                <div style={styles.kioskContainer(isMobile)}>
                    <header style={{textAlign: 'center' as const, marginBottom: isMobile ? '1.5rem' : '3rem'}}>
                        <h1 style={{margin: 0, fontSize: isMobile ? '2rem' : '3.5rem', color: colors.primaryPink, fontWeight: '900', letterSpacing: '2px'}}>THE PINK ELEPHANT</h1>
                        <p style={{margin: 0, letterSpacing: '4px', color: colors.mediumGray, fontSize: '0.75rem'}}>TATTOO & PIERCING STUDIO</p>
                    </header>

                    <div style={styles.kioskCard(isMobile)}>
                        {view === 'menu' && (
                            <div style={{display: 'flex' as const, flexDirection: 'column' as const, gap: '1rem'}}>
                                <h3 style={{textAlign: 'center' as const, color: colors.darkGray, marginBottom: '1rem'}}>Select a service to begin</h3>
                                <button onClick={() => setView('tattoo')} style={{...styles.button, ...styles.primaryBtn, padding: '2.5rem', fontSize: '1.4rem'}}>🎨 TATTOO CONSENT</button>
                                <button onClick={() => setView('piercing')} style={{...styles.button, backgroundColor: colors.purple, color: colors.white, padding: '2.5rem', fontSize: '1.4rem'}}>💎 PIERCING CONSENT</button>
                                <button onClick={() => setView('minor')} style={{...styles.button, backgroundColor: colors.warningAmber, color: colors.white, padding: '2.5rem', fontSize: '1.4rem'}}>👶 MINOR CONSENT</button>
                                <button onClick={() => setPasscodeModal(true)} style={{marginTop: '2rem', background: 'none', border: 'none', color: colors.lightGray, cursor: 'pointer', fontSize: '0.9rem'}}>Staff Login</button>
                            </div>
                        )}
                        {(view === 'tattoo' || view === 'piercing' || view === 'minor') && <ConsentForm isMobile={isMobile} type={view} onBack={() => setView('menu')} onSubmit={handleSubmission} />}
                        {view === 'success' && (
                            <div style={{textAlign: 'center' as const, padding: isMobile ? '1rem' : '4rem'}}>
                                <div style={{fontSize: '6rem', color: colors.successGreen}}>✓</div>
                                <h2 style={{fontSize: '2rem', margin: '1rem 0', color: colors.textColor}}>Submission Received!</h2>
                                <p style={{color: colors.mediumGray, fontSize: '1.1rem'}}>Please notify your artist or wait for your name to be called.</p>
                                <button onClick={() => setView('menu')} style={{...styles.button, ...styles.primaryBtn, marginTop: '2rem', padding: '1.25rem 3rem'}}>DONE</button>
                            </div>
                        )}
                    </div>
                </div>
            )}

